import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import Hero from './components/Hero';
import AboutSection from './components/AboutSection';
import YouTubeSlider from './components/YouTubeSlider';
import TwitterCard from './components/TwitterCard';
import FacebookSection from './components/FacebookSection';
import Testimonials, { INITIAL_TESTIMONIALS } from './components/Testimonials';
import Footer from './components/Footer';
import ArticlesPage from './components/ArticlesPage';
import LoginPage from './components/admin/LoginPage';
import Dashboard from './components/admin/Dashboard';
import { Section, AppView, Testimonial } from './types';

const App: React.FC = () => {
  const [activeSection, setActiveSection] = useState<Section>(Section.HOME);
  const [currentView, setCurrentView] = useState<AppView>('home');
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [testimonials, setTestimonials] = useState<Testimonial[]>(INITIAL_TESTIMONIALS);

  // Handle Routing (Pathname + Hash)
  useEffect(() => {
    const handleRouteCheck = () => {
      const path = window.location.pathname;
      const hash = window.location.hash;

      // Check for direct /login path OR #login hash
      if (path === '/login' || hash === '#login') {
        setCurrentView('login');
      } else if (hash === '#dashboard') {
        setCurrentView('dashboard');
      } else if (hash === '#articles') {
        setCurrentView('articles');
      } else {
        // Only reset to home if we are not already on a specific valid view
        if (path === '/' && !hash) {
            setCurrentView('home');
        }

        // Handle in-page section scrolling
        if (hash.startsWith('#section-')) {
            const sectionId = hash.replace('#section-', '') as Section;
            // Use currentView check to avoid race conditions if switching from another view
            if (currentView !== 'home') {
                setCurrentView('home');
                setTimeout(() => {
                    const element = document.getElementById(sectionId);
                    if (element) element.scrollIntoView({ behavior: 'smooth' });
                }, 100);
            } else {
                 const element = document.getElementById(sectionId);
                 if (element) element.scrollIntoView({ behavior: 'smooth' });
            }
        }
      }
    };

    // Check initially
    handleRouteCheck();

    // Listen for changes
    window.addEventListener('popstate', handleRouteCheck); // Handles browser back/forward
    window.addEventListener('hashchange', handleRouteCheck); // Handles hash changes

    return () => {
        window.removeEventListener('popstate', handleRouteCheck);
        window.removeEventListener('hashchange', handleRouteCheck);
    };
  }, [currentView]);

  // Load testimonials from localStorage
  useEffect(() => {
    const saved = localStorage.getItem('gamil_testimonials');
    if (saved) {
        try {
            setTestimonials(JSON.parse(saved));
        } catch (e) {
            console.error("Failed to parse saved testimonials");
        }
    }
  }, []);

  // Save to localStorage whenever testimonials change
  useEffect(() => {
      localStorage.setItem('gamil_testimonials', JSON.stringify(testimonials));
  }, [testimonials]);

  // Handle scroll spy
  useEffect(() => {
    if (currentView !== 'home') return;

    const handleScroll = () => {
      const sections = Object.values(Section);
      for (const section of sections) {
        const element = document.getElementById(section);
        if (element) {
          const rect = element.getBoundingClientRect();
          if (rect.top >= -100 && rect.top <= 300) {
            setActiveSection(section);
            break;
          }
        }
      }
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, [currentView]);

  const scrollToSection = (sectionId: Section) => {
    if (currentView !== 'home') {
        setCurrentView('home');
        // Small timeout to allow render
        setTimeout(() => {
             const element = document.getElementById(sectionId);
             if (element) element.scrollIntoView({ behavior: 'smooth' });
             history.pushState(null, '', `/#section-${sectionId}`);
        }, 50);
    } else {
        const element = document.getElementById(sectionId);
        if (element) {
            element.scrollIntoView({ behavior: 'smooth' });
        }
        history.pushState(null, '', `/#section-${sectionId}`);
    }
    setActiveSection(sectionId);
  };

  const navigateToArticles = () => {
      window.location.hash = '#articles';
      setCurrentView('articles');
  };

  const navigateHome = () => {
      history.pushState(null, '', '/');
      setCurrentView('home');
      window.scrollTo({ top: 0, behavior: 'smooth' });
  }

  const handleLogin = (success: boolean) => {
      if (success) {
          setIsAuthenticated(true);
          window.location.hash = '#dashboard';
          setCurrentView('dashboard');
      }
  };

  const handleLogout = () => {
      setIsAuthenticated(false);
      navigateHome();
  };

  const handleUpdateTestimonials = (newItems: Testimonial[]) => {
      setTestimonials(newItems);
  };

  // Render logic based on state
  if (currentView === 'login') {
      return <LoginPage onLogin={handleLogin} />;
  }

  if (currentView === 'dashboard') {
      if (!isAuthenticated) return <LoginPage onLogin={handleLogin} />;
      return <Dashboard items={testimonials} onUpdateItems={handleUpdateTestimonials} onLogout={handleLogout} />;
  }

  return (
    <div className="font-sans text-slate-900 bg-white min-h-screen">
      <Header 
        activeSection={activeSection} 
        activeView={currentView}
        scrollToSection={scrollToSection} 
        onNavigateHome={navigateHome}
      />

      <main>
        {currentView === 'home' ? (
            <>
                <Hero scrollToSection={scrollToSection} />
                <AboutSection onNavigateToArticles={navigateToArticles} />
                <YouTubeSlider />
                <TwitterCard />
                <FacebookSection />
                <Testimonials items={testimonials} />
            </>
        ) : (
            <ArticlesPage onBack={navigateHome} />
        )}
      </main>

      <Footer scrollToSection={scrollToSection} />
    </div>
  );
};

export default App;

