import React, { useState } from 'react';
import { Testimonial, Video } from '../../types';
import { Trash2, Plus, Image as ImageIcon, Type, LogOut, LayoutDashboard, Video as VideoIcon, Quote } from 'lucide-react';

interface DashboardProps {
    testimonials: Testimonial[];
    videos: Video[];
    onUpdateTestimonials: (items: Testimonial[]) => void;
    onUpdateVideos: (items: Video[]) => void;
    onLogout: () => void;
}

type Tab = 'testimonials' | 'videos';

const Dashboard: React.FC<DashboardProps> = ({ testimonials, videos, onUpdateTestimonials, onUpdateVideos, onLogout }) => {
    const [activeTab, setActiveTab] = useState<Tab>('testimonials');

    // Testimonial State
    const [newItemType, setNewItemType] = useState<'text' | 'image'>('image');
    const [newAuthor, setNewAuthor] = useState('');
    const [newRole, setNewRole] = useState('');
    const [newContent, setNewContent] = useState('');
    const [newImage, setNewImage] = useState<string>('');

    // Video State
    const [videoUrl, setVideoUrl] = useState('');
    const [videoTitle, setVideoTitle] = useState('');

    const handleDeleteTestimonial = (id: string | number) => {
        if (window.confirm('هل أنت متأكد من حذف هذا العنصر؟')) {
            onUpdateTestimonials(testimonials.filter(item => item.id !== id));
        }
    };

    const handleDeleteVideo = (id: string) => {
        if (window.confirm('هل أنت متأكد من حذف هذا الفيديو؟')) {
            onUpdateVideos(videos.filter(item => item.id !== id));
        }
    };

    const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = () => {
                setNewImage(reader.result as string);
            };
            reader.readAsDataURL(file);
        }
    };

    const handleAddTestimonial = (e: React.FormEvent) => {
        e.preventDefault();
        const newItem: Testimonial = {
            id: Date.now(),
            type: newItemType,
            author: newItemType === 'text' ? newAuthor : undefined,
            role: newItemType === 'text' ? newRole : undefined,
            content: newItemType === 'text' ? newContent : undefined,
            src: newItemType === 'image' ? newImage : undefined
        };
        onUpdateTestimonials([newItem, ...testimonials]);
        setNewAuthor(''); setNewRole(''); setNewContent(''); setNewImage('');
        alert('تمت الإضافة بنجاح');
    };

    const handleAddVideo = (e: React.FormEvent) => {
        e.preventDefault();

        // Extract YouTube ID
        let videoId = '';
        try {
            if (videoUrl.includes('v=')) {
                videoId = videoUrl.split('v=')[1].split('&')[0];
            } else if (videoUrl.includes('youtu.be/')) {
                videoId = videoUrl.split('youtu.be/')[1].split('?')[0];
            }
        } catch (e) {
            alert('الرابط غير صحيح');
            return;
        }

        if (!videoId) {
            alert('لم يتم التعرف على معرف الفيديو. تأكد من الرابط.');
            return;
        }

        const newVideo: Video = {
            id: videoId,
            title: videoTitle,
            url: videoUrl,
            thumbnail: `https://i.ytimg.com/vi/${videoId}/hqdefault.jpg`,
            date: new Date().toLocaleDateString('ar-EG'),
            views: 'جديد'
        };

        onUpdateVideos([newVideo, ...videos]);
        setVideoUrl('');
        setVideoTitle('');
        alert('تمت إضافة الفيديو بنجاح');
    };

    return (
        <div className="min-h-screen bg-gray-100 flex flex-col">
            {/* Top Bar */}
            <div className="bg-slate-900 text-white p-4 shadow-md flex justify-between items-center sticky top-0 z-50">
                <div className="flex items-center gap-3">
                    <LayoutDashboard className="text-gold-500" />
                    <h1 className="font-heading font-bold text-xl">لوحة التحكم</h1>
                </div>
                <button 
                    onClick={onLogout}
                    className="flex items-center gap-2 text-sm bg-slate-800 hover:bg-slate-700 px-4 py-2 rounded-lg transition-colors"
                >
                    <LogOut size={16} />
                    تسجيل خروج
                </button>
            </div>

            <div className="container mx-auto p-4 md:p-6">

                {/* Tabs */}
                <div className="flex gap-4 mb-8 bg-white p-2 rounded-xl shadow-sm max-w-md">
                    <button 
                        onClick={() => setActiveTab('testimonials')}
                        className={`flex-1 py-3 rounded-lg font-bold flex items-center justify-center gap-2 transition-all ${activeTab === 'testimonials' ? 'bg-slate-900 text-white shadow' : 'text-gray-500 hover:bg-gray-50'}`}
                    >
                        <Quote size={20} />
                        ماذا قيل عنه
                    </button>
                    <button 
                        onClick={() => setActiveTab('videos')}
                        className={`flex-1 py-3 rounded-lg font-bold flex items-center justify-center gap-2 transition-all ${activeTab === 'videos' ? 'bg-red-600 text-white shadow' : 'text-gray-500 hover:bg-gray-50'}`}
                    >
                        <VideoIcon size={20} />
                        الفيديوهات
                    </button>
                </div>

                <div className="grid lg:grid-cols-3 gap-8">
                    {/* Input Form */}
                    <div className="lg:col-span-1">
                        <div className="bg-white p-6 rounded-xl shadow-md sticky top-24">
                            <h2 className="text-xl font-bold mb-6 border-b pb-2 flex items-center gap-2">
                                <Plus size={20} className={activeTab === 'videos' ? 'text-red-500' : 'text-gold-500'} />
                                {activeTab === 'testimonials' ? 'إضافة رأي جديد' : 'إضافة فيديو جديد'}
                            </h2>

                            {activeTab === 'testimonials' ? (
                                <form onSubmit={handleAddTestimonial} className="space-y-4">
                                    <div className="flex gap-2 p-1 bg-gray-100 rounded-lg mb-4">
                                        <button type="button" onClick={() => setNewItemType('image')} className={`flex-1 py-2 text-sm font-bold rounded-md flex items-center justify-center gap-2 transition-all ${newItemType === 'image' ? 'bg-white shadow text-blue-600' : 'text-gray-500'}`}>
                                            <ImageIcon size={16} /> صورة
                                        </button>
                                        <button type="button" onClick={() => setNewItemType('text')} className={`flex-1 py-2 text-sm font-bold rounded-md flex items-center justify-center gap-2 transition-all ${newItemType === 'text' ? 'bg-white shadow text-blue-600' : 'text-gray-500'}`}>
                                            <Type size={16} /> نص
                                        </button>
                                    </div>
                                    {newItemType === 'image' ? (
                                        <div className="border-2 border-dashed border-gray-300 rounded-lg p-6 text-center hover:border-blue-500 transition-colors bg-gray-50">
                                            <input type="file" accept="image/*" onChange={handleImageUpload} className="hidden" id="image-upload"/>
                                            <label htmlFor="image-upload" className="cursor-pointer flex flex-col items-center gap-2">
                                                {newImage ? <img src={newImage} alt="Preview" className="max-h-40 rounded shadow" /> : <><ImageIcon className="w-12 h-12 text-gray-300" /><span className="text-sm text-gray-500">رفع صورة</span></>}
                                            </label>
                                        </div>
                                    ) : (
                                        <div className="space-y-4">
                                            <input type="text" placeholder="اسم القائل" value={newAuthor} onChange={(e) => setNewAuthor(e.target.value)} className="w-full border p-3 rounded-lg" required />
                                            <input type="text" placeholder="الصفة / المنصب" value={newRole} onChange={(e) => setNewRole(e.target.value)} className="w-full border p-3 rounded-lg" required />
                                            <textarea placeholder="نص الاقتباس..." value={newContent} onChange={(e) => setNewContent(e.target.value)} className="w-full border p-3 rounded-lg h-32" required />
