                                    {testimonials.map((item) => (
                                        <div key={item.id} className="bg-white p-4 rounded-xl shadow border border-gray-100 flex gap-4 group">
                                            <div className="w-20 h-20 bg-gray-100 rounded-lg overflow-hidden flex-shrink-0">
