                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        ) : (
                            <div className="space-y-4">
                                <h2 className="text-xl font-bold mb-4">مكتبة الفيديو ({videos.length})</h2>
                                <div className="grid md:grid-cols-2 gap-4">
                                    {videos.map((video) => (
                                        <div key={video.id} className="bg-white p-3 rounded-xl shadow border border-gray-100 flex gap-4 group hover:border-red-200 transition-colors">
                                            <div className="w-32 h-20 bg-black rounded-lg overflow-hidden flex-shrink-0 relative">
                                                <img src={video.thumbnail} alt={video.title} className="w-full h-full object-cover opacity-80" />
                                                <div className="absolute inset-0 flex items-center justify-center"><div className="w-6 h-6 bg-white/20 rounded-full flex items-center justify-center"><div className="w-0 h-0 border-t-[4px] border-t-transparent border-l-[8px] border-l-white border-b-[4px] border-b-transparent ml-0.5"></div></div></div>
                                            </div>
                                            <div className="flex-1 flex flex-col">
                                                <h4 className="font-bold text-sm text-slate-800 line-clamp-2 mb-1">{video.title}</h4>
                                                <p className="text-xs text-gray-500 mb-2 dir-ltr text-right truncate">{video.id}</p>
                                                <div className="mt-auto flex justify-end">
                                                    <button onClick={() => handleDeleteVideo(video.id)} className="flex items-center gap-1 text-red-500 text-xs font-bold hover:bg-red-50 px-2 py-1 rounded transition-colors">
                                                        <Trash2 size={12} /> حذف
                                                    </button>
                                                </div>
                                            </div>
                                        </div>
                                    ))}
                                    {videos.length === 0 && (
                                        <div className="col-span-2 text-center py-8 text-gray-400">لا توجد فيديوهات. أضف أول فيديو من النموذج.</div>
                                    )}
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

