import { GoogleGenAI, Type } from "@google/genai";

const apiKey = process.env.API_KEY || '';

// Fallback content if API key is missing
const FALLBACK_BIO = `جميل عزالدين، إعلامي يمني بارز وصوت وطني حر. يشغل منصب رئيس قطاع التلفزيون في الفضائية اليمنية، وعميد في التوجيه المعنوي. عرف بأسلوبه الخطابي المفوه وحضوره القوي في المشهد الإعلامي اليمني، مدافعاً عن الثوابت الوطنية والجمهورية. يتميز ببرامجه التي تلامس هموم المواطن وتنقل الحقائق من قلب الحدث.`;

export const getBio = async (): Promise<string> => {
  if (!apiKey) return FALLBACK_BIO;

  try {
    const ai = new GoogleGenAI({ apiKey });
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: `اكتب سيرة ذاتية احترافية وملهمة (حوالي 60 كلمة) للاعلامي اليمني الشهير "جميل عزالدين". ركز على دوره الوطني، بلاغته، ومنصبه كإعلامي بارز في اليمن. النص يجب أن يكون باللغة العربية الفصحى القوية.`,
    });
    return response.text || FALLBACK_BIO;
  } catch (error) {
    console.error("Gemini API Error:", error);
    return FALLBACK_BIO;
  }
};

export const getLatestTweetContent = async (): Promise<string> => {
   if (!apiKey) return "الجمهورية هي الحصن الحصين لكل اليمنيين، والدفاع عنها واجب مقدس لا يقبل المساومة. نحن هنا، وسنظل هنا، أصواتاً تصدح بالحق حتى يعود الوطن معافى.";

   try {
    const ai = new GoogleGenAI({ apiKey });
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: `تخيل أنك الاعلامي جميل عزالدين، اكتب تغريدة حماسية قصيرة (أقل من 200 حرف) تتحدث عن حب الوطن والصمود، بأسلوبه البلاغي المعروف.`,
    });
    return response.text || "تحيا الجمهورية اليمنية.";
   } catch (error) {
     return "الوطن غالي، والجمهورية هي الخيار الوحيد.";
   }
}

export const analyzeImageForTestimonial = async (base64Image: string): Promise<{content: string, author: string, role: string}> => {
  if (!apiKey) throw new Error("API Key missing");

  try {
    const ai = new GoogleGenAI({ apiKey });

    // Clean base64 string
    const cleanBase64 = base64Image.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, '');

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg', // Assuming jpeg/png, API is flexible
              data: cleanBase64
            }
          },
          {
            text: "قم بتحليل هذه الصورة. استخرج النص الموجود فيها كاملاً (الاقتباس). استخرج اسم الشخص الذي كتب النص أو صاحب الاقتباس (المؤلف). استخرج صفته أو منصبه إن وجد. أعد النتيجة بتنسيق JSON."
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            content: { type: Type.STRING, description: "The full text/quote found in the image" },
            author: { type: Type.STRING, description: "The name of the person who said/wrote it" },
            role: { type: Type.STRING, description: "The job title or role of the person" },
          },
          required: ["content", "author"],
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text);
  } catch (error) {
    console.error("Image analysis failed:", error);
    return {
      content: "",
      author: "",
      role: ""
    };
  }
};

import React, { useState } from 'react';
import { Testimonial, Video } from '../../types';
import { Trash2, Plus, Image as ImageIcon, Type, LogOut, LayoutDashboard, Video as VideoIcon, Quote, Loader2, Sparkles } from 'lucide-react';
import { analyzeImageForTestimonial } from '../../services/geminiService';

interface DashboardProps {
    testimonials: Testimonial[];
    videos: Video[];
    onUpdateTestimonials: (items: Testimonial[]) => void;
    onUpdateVideos: (items: Video[]) => void;
    onLogout: () => void;
}

type Tab = 'testimonials' | 'videos';

const Dashboard: React.FC<DashboardProps> = ({ testimonials, videos, onUpdateTestimonials, onUpdateVideos, onLogout }) => {
    const [activeTab, setActiveTab] = useState<Tab>('testimonials');

    // Testimonial State
    const [newItemType, setNewItemType] = useState<'text' | 'image' | 'mixed'>('image');
    const [newAuthor, setNewAuthor] = useState('');
    const [newRole, setNewRole] = useState('');
    const [newContent, setNewContent] = useState('');
    const [newImage, setNewImage] = useState<string>('');
    const [isAnalyzing, setIsAnalyzing] = useState(false);

    // Video State
    const [videoUrl, setVideoUrl] = useState('');
    const [videoTitle, setVideoTitle] = useState('');

    const handleDeleteTestimonial = (id: string | number) => {
        if (window.confirm('هل أنت متأكد من حذف هذا العنصر؟')) {
            onUpdateTestimonials(testimonials.filter(item => item.id !== id));
        }
    };

    const handleDeleteVideo = (id: string) => {
        if (window.confirm('هل أنت متأكد من حذف هذا الفيديو؟')) {
            onUpdateVideos(videos.filter(item => item.id !== id));
        }
    };

    const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = async () => {
                const base64 = reader.result as string;
                setNewImage(base64);

                // Start AI Analysis
                setIsAnalyzing(true);
                try {
                    const analysis = await analyzeImageForTestimonial(base64);
                    if (analysis.content || analysis.author) {
                        setNewContent(analysis.content || '');
                        setNewAuthor(analysis.author || 'غير معروف');
                        setNewRole(analysis.role || '');
                        // Switch to mixed mode to show text fields + image
                        setNewItemType('mixed');
                    }
                } catch (error) {
                    console.error("Failed to analyze image", error);
                } finally {
                    setIsAnalyzing(false);
                }
            };
            reader.readAsDataURL(file);
        }
    };

    const handleAddTestimonial = (e: React.FormEvent) => {
        e.preventDefault();
        const newItem: Testimonial = {
            id: Date.now(),
            type: newItemType,
            author: (newItemType === 'text' || newItemType === 'mixed') ? newAuthor : undefined,
            role: (newItemType === 'text' || newItemType === 'mixed') ? newRole : undefined,
            content: (newItemType === 'text' || newItemType === 'mixed') ? newContent : undefined,
            src: (newItemType === 'image' || newItemType === 'mixed') ? newImage : undefined
        };
        onUpdateTestimonials([newItem, ...testimonials]);

        // Reset form
        setNewAuthor(''); 
        setNewRole(''); 
        setNewContent(''); 
        setNewImage('');
        setNewItemType('image'); // Reset to default

        alert('تمت الإضافة بنجاح');
    };

    const handleAddVideo = (e: React.FormEvent) => {
        e.preventDefault();

        // Extract YouTube ID
        let videoId = '';
        try {
            if (videoUrl.includes('v=')) {
                videoId = videoUrl.split('v=')[1].split('&')[0];
            } else if (videoUrl.includes('youtu.be/')) {
                videoId = videoUrl.split('youtu.be/')[1].split('?')[0];
            }
        } catch (e) {
            alert('الرابط غير صحيح');
            return;
        }

        if (!videoId) {
            alert('لم يتم التعرف على معرف الفيديو. تأكد من الرابط.');
            return;
        }

        const newVideo: Video = {
            id: videoId,
            title: videoTitle,
            url: videoUrl,
            thumbnail: `https://i.ytimg.com/vi/${videoId}/hqdefault.jpg`,
            date: new Date().toLocaleDateString('ar-EG'),
            views: 'جديد'
        };

        onUpdateVideos([newVideo, ...videos]);
        setVideoUrl('');
        setVideoTitle('');
        alert('تمت إضافة الفيديو بنجاح');
    };

    return (
        <div className="min-h-screen bg-gray-100 flex flex-col">
            {/* Top Bar */}
            <div className="bg-slate-900 text-white p-4 shadow-md flex justify-between items-center sticky top-0 z-50">
                <div className="flex items-center gap-3">
                    <LayoutDashboard className="text-gold-500" />
                    <h1 className="font-heading font-bold text-xl">لوحة التحكم</h1>
                </div>
                <button 
                    onClick={onLogout}
                    className="flex items-center gap-2 text-sm bg-slate-800 hover:bg-slate-700 px-4 py-2 rounded-lg transition-colors"
                >
                    <LogOut size={16} />
                    تسجيل خروج
                </button>
            </div>

            <div className="container mx-auto p-4 md:p-6">

                {/* Tabs */}
                <div className="flex gap-4 mb-8 bg-white p-2 rounded-xl shadow-sm max-w-md">
                    <button 
                        onClick={() => setActiveTab('testimonials')}
                        className={`flex-1 py-3 rounded-lg font-bold flex items-center justify-center gap-2 transition-all ${activeTab === 'testimonials' ? 'bg-slate-900 text-white shadow' : 'text-gray-500 hover:bg-gray-50'}`}
                    >
                        <Quote size={20} />
                        ماذا قيل عنه
                    </button>
                    <button 
                        onClick={() => setActiveTab('videos')}
                        className={`flex-1 py-3 rounded-lg font-bold flex items-center justify-center gap-2 transition-all ${activeTab === 'videos' ? 'bg-red-600 text-white shadow' : 'text-gray-500 hover:bg-gray-50'}`}
                    >
                        <VideoIcon size={20} />
                        الفيديوهات
                    </button>
                </div>

                <div className="grid lg:grid-cols-3 gap-8">
                    {/* Input Form */}
                    <div className="lg:col-span-1">
                        <div className="bg-white p-6 rounded-xl shadow-md sticky top-24">
                            <h2 className="text-xl font-bold mb-6 border-b pb-2 flex items-center gap-2">
                                <Plus size={20} className={activeTab === 'videos' ? 'text-red-500' : 'text-gold-500'} />
                                {activeTab === 'testimonials' ? 'إضافة رأي جديد' : 'إضافة فيديو جديد'}
                            </h2>

                            {activeTab === 'testimonials' ? (
                                <form onSubmit={handleAddTestimonial} className="space-y-4">
                                    <div className="flex gap-2 p-1 bg-gray-100 rounded-lg mb-4">
                                        <button type="button" onClick={() => setNewItemType('image')} className={`flex-1 py-2 text-sm font-bold rounded-md flex items-center justify-center gap-2 transition-all ${newItemType === 'image' ? 'bg-white shadow text-blue-600' : 'text-gray-500'}`}>
                                            <ImageIcon size={16} /> صورة
                                        </button>
                                        <button type="button" onClick={() => setNewItemType('text')} className={`flex-1 py-2 text-sm font-bold rounded-md flex items-center justify-center gap-2 transition-all ${newItemType === 'text' ? 'bg-white shadow text-blue-600' : 'text-gray-500'}`}>
                                            <Type size={16} /> نص
                                        </button>
                                        <button type="button" onClick={() => setNewItemType('mixed')} className={`flex-1 py-2 text-sm font-bold rounded-md flex items-center justify-center gap-2 transition-all ${newItemType === 'mixed' ? 'bg-white shadow text-purple-600' : 'text-gray-500'}`}>
                                            <Sparkles size={16} /> ذكي
                                        </button>
                                    </div>

                                    {/* Image Upload Area */}
                                    {(newItemType === 'image' || newItemType === 'mixed') && (
                                        <div className={`border-2 border-dashed rounded-lg p-6 text-center transition-colors bg-gray-50 relative ${newItemType === 'mixed' ? 'border-purple-300 bg-purple-50' : 'border-gray-300 hover:border-blue-500'}`}>
                                            <input type="file" accept="image/*" onChange={handleImageUpload} className="hidden" id="image-upload"/>
                                            <label htmlFor="image-upload" className="cursor-pointer flex flex-col items-center gap-2">
                                                {newImage ? (
                                                    <img src={newImage} alt="Preview" className="max-h-40 rounded shadow" />
                                                ) : (
                                                    <>
                                                        <ImageIcon className={`w-12 h-12 ${newItemType === 'mixed' ? 'text-purple-300' : 'text-gray-300'}`} />
                                                        <span className="text-sm text-gray-500">
                                                            {newItemType === 'mixed' ? 'ارفع صورة لاستخراج النص منها' : 'رفع صورة'}
                                                        </span>
                                                    </>
                                                )}
                                            </label>
                                            {isAnalyzing && (
                                                <div className="absolute inset-0 bg-white/80 flex flex-col items-center justify-center rounded-lg">
                                                    <Loader2 className="w-8 h-8 text-gold-500 animate-spin mb-2" />
                                                    <span className="text-sm font-bold text-slate-700">جاري تحليل النص...</span>
                                                </div>
                                            )}
                                        </div>
                                    )}

                                    {/* Text Inputs */}
                                    {(newItemType === 'text' || newItemType === 'mixed') && (
                                        <div className="space-y-4 animate-fade-in">
                                            {newItemType === 'mixed' && (
                                                <div className="bg-purple-100 text-purple-800 p-3 rounded text-sm mb-2 border border-purple-200">
