                                            <div>
                                                <label className="text-xs font-bold text-gray-500 mb-1 block">نص الاقتباس</label>
                                                <textarea placeholder="نص الاقتباس..." value={newContent} onChange={(e) => setNewContent(e.target.value)} className="w-full border p-3 rounded-lg h-32" required />
                                            </div>
                                            <div>
                                                <label className="text-xs font-bold text-gray-500 mb-1 block">القائل / المؤلف</label>
                                                <input type="text" placeholder="اسم القائل" value={newAuthor} onChange={(e) => setNewAuthor(e.target.value)} className="w-full border p-3 rounded-lg" required />
                                            </div>
                                            <div>
                                                <label className="text-xs font-bold text-gray-500 mb-1 block">الصفة / المنصب</label>
                                                <input type="text" placeholder="الصفة / المنصب" value={newRole} onChange={(e) => setNewRole(e.target.value)} className="w-full border p-3 rounded-lg" />
                                            </div>
                                        </div>
