                                    <button 
                                        type="submit" 
                                        disabled={(newItemType !== 'text' && !newImage) || (newItemType !== 'image' && !newContent)} 
                                        className={`w-full font-bold py-3 rounded-lg transition-colors text-white ${newItemType === 'mixed' ? 'bg-purple-600 hover:bg-purple-700' : 'bg-slate-900 hover:bg-slate-800'}`}
                                    >
                                        {newItemType === 'mixed' ? 'نشر الاقتباس والصورة' : 'نشر'}
                                    </button>
                                </form>
                            ) : (
                                <form onSubmit={handleAddVideo} className="space-y-4">
                                    <div>
                                        <label className="block text-sm font-bold text-gray-700 mb-2">رابط الفيديو (YouTube URL)</label>
                                        <input 
                                            type="text" 
                                            placeholder="https://www.youtube.com/watch?v=..." 
                                            value={videoUrl} 
                                            onChange={(e) => setVideoUrl(e.target.value)} 
                                            className="w-full border p-3 rounded-lg dir-ltr text-left" 
                                            required 
                                        />
                                        <p className="text-xs text-gray-400 mt-1">انسخ الرابط من المتصفح مباشرة</p>
