import { Testimonial, Video } from '../types';

const KEYS = {
  TESTIMONIALS: 'gamil_testimonials',
  VIDEOS: 'gamil_videos'
};

// Default Data (Used only if database is empty)
export const INITIAL_VIDEOS: Video[] = [];
export const INITIAL_TESTIMONIALS: Testimonial[] = [
    { id: 1, type: 'text', content: "جميل عزالدين ليس مجرد إعلامي، بل هو جبهة إعلامية بحد ذاته.", author: "د. محمد العامري", role: "مستشار رئاسي" },
    { id: 2, type: 'text', content: "الروح الوطنية التي يتمتع بها العميد جميل عزالدين تلهمنا جميعاً.", author: "ناشط سياسي", role: "تويتر" },
];

export const StorageService = {
  // --- Testimonials Operations ---
  getTestimonials: (): Testimonial[] => {
    if (typeof window === 'undefined') return INITIAL_TESTIMONIALS;
    try {
      const data = localStorage.getItem(KEYS.TESTIMONIALS);
      return data ? JSON.parse(data) : INITIAL_TESTIMONIALS;
    } catch (error) {
      console.error('Error reading testimonials from DB:', error);
      return INITIAL_TESTIMONIALS;
    }
  },

  saveTestimonials: (items: Testimonial[]): boolean => {
    try {
      localStorage.setItem(KEYS.TESTIMONIALS, JSON.stringify(items));
      return true;
    } catch (error: any) {
      if (error.name === 'QuotaExceededError') {
        alert('مساحة التخزين ممتلئة! الصور المحملة كبيرة جداً. حاول حذف بعض العناصر القديمة.');
      }
      console.error('Error saving testimonials to DB:', error);
      return false;
    }
  },

  // --- Videos Operations ---
  getVideos: (): Video[] => {
    if (typeof window === 'undefined') return INITIAL_VIDEOS;
    try {
      const data = localStorage.getItem(KEYS.VIDEOS);
      return data ? JSON.parse(data) : INITIAL_VIDEOS;
    } catch (error) {
      console.error('Error reading videos from DB:', error);
      return INITIAL_VIDEOS;
    }
  },

  saveVideos: (items: Video[]): boolean => {
    try {
      localStorage.setItem(KEYS.VIDEOS, JSON.stringify(items));
      return true;
    } catch (error) {
      console.error('Error saving videos to DB:', error);
      alert('حدث خطأ أثناء حفظ الفيديو.');
      return false;
    }
  }
};

import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import Hero from './components/Hero';
import AboutSection from './components/AboutSection';
import YouTubeSlider from './components/YouTubeSlider';
import TwitterCard from './components/TwitterCard';
import FacebookSection from './components/FacebookSection';
import Testimonials from './components/Testimonials';
import Footer from './components/Footer';
import ArticlesPage from './components/ArticlesPage';
import LoginPage from './components/admin/LoginPage';
import Dashboard from './components/admin/Dashboard';
import { Section, AppView, Testimonial, Video } from './types';
import { StorageService } from './services/storage';

const App: React.FC = () => {
  const [activeSection, setActiveSection] = useState<Section>(Section.HOME);
  const [currentView, setCurrentView] = useState<AppView>('home');
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  // Lazy Initialization: Read from DB immediately on load
  const [testimonials, setTestimonials] = useState<Testimonial[]>(() => StorageService.getTestimonials());
  const [videos, setVideos] = useState<Video[]>(() => StorageService.getVideos());

  // Handle Routing
  useEffect(() => {
    const handleRouteCheck = () => {
      const path = window.location.pathname;
      const hash = window.location.hash;

      if (path === '/login' || hash === '#login') {
        setCurrentView('login');
      } else if (hash === '#dashboard') {
        setCurrentView('dashboard');
      } else if (hash === '#articles') {
        setCurrentView('articles');
      } else {
        if (path === '/' && !hash) setCurrentView('home');

        if (hash.startsWith('#section-')) {
            const sectionId = hash.replace('#section-', '') as Section;
            if (currentView !== 'home') {
                setCurrentView('home');
                setTimeout(() => {
                    const element = document.getElementById(sectionId);
                    if (element) element.scrollIntoView({ behavior: 'smooth' });
                }, 100);
            } else {
                 const element = document.getElementById(sectionId);
                 if (element) element.scrollIntoView({ behavior: 'smooth' });
            }
        }
      }
    };

    handleRouteCheck();
    window.addEventListener('popstate', handleRouteCheck);
    window.addEventListener('hashchange', handleRouteCheck);
    return () => {
        window.removeEventListener('popstate', handleRouteCheck);
        window.removeEventListener('hashchange', handleRouteCheck);
    };
  }, [currentView]);

  // Handle Database Updates
  const handleUpdateTestimonials = (newItems: Testimonial[]) => {
      setTestimonials(newItems);
      StorageService.saveTestimonials(newItems); // Save to DB
  };

  const handleUpdateVideos = (newVideos: Video[]) => {
      setVideos(newVideos);
      StorageService.saveVideos(newVideos); // Save to DB
  };

  const scrollToSection = (sectionId: Section) => {
    if (currentView !== 'home') {
        setCurrentView('home');
        setTimeout(() => {
             const element = document.getElementById(sectionId);
             if (element) element.scrollIntoView({ behavior: 'smooth' });
             history.pushState(null, '', `/#section-${sectionId}`);
        }, 50);
    } else {
        const element = document.getElementById(sectionId);
        if (element) {
            element.scrollIntoView({ behavior: 'smooth' });
        }
        history.pushState(null, '', `/#section-${sectionId}`);
    }
    setActiveSection(sectionId);
  };

  const navigateHome = () => {
      history.pushState(null, '', '/');
      setCurrentView('home');
      window.scrollTo({ top: 0, behavior: 'smooth' });
  }

  const handleLogin = (success: boolean) => {
      if (success) {
          setIsAuthenticated(true);
          window.location.hash = '#dashboard';
          setCurrentView('dashboard');
      }
  };

  const handleLogout = () => {
      setIsAuthenticated(false);
      navigateHome();
  };

  if (currentView === 'login') {
      return <LoginPage onLogin={handleLogin} />;
  }

  if (currentView === 'dashboard') {
      if (!isAuthenticated) return <LoginPage onLogin={handleLogin} />;
      return (
        <Dashboard 
            testimonials={testimonials} 
            videos={videos}
            onUpdateTestimonials={handleUpdateTestimonials} 
            onUpdateVideos={handleUpdateVideos}
            onLogout={handleLogout} 
        />
      );
  }

  return (
    <div className="font-sans text-slate-900 bg-white min-h-screen">
      <Header 
        activeSection={activeSection} 
        activeView={currentView}
        scrollToSection={scrollToSection} 
        onNavigateHome={navigateHome}
      />

      <main>
        {currentView === 'home' ? (
            <>
                <Hero scrollToSection={scrollToSection} />
                <AboutSection onNavigateToArticles={() => { window.location.hash = '#articles'; setCurrentView('articles'); }} />
                <YouTubeSlider videos={videos} />
                <TwitterCard />
                <FacebookSection />
                <Testimonials items={testimonials} />
            </>
        ) : (
            <ArticlesPage onBack={navigateHome} />
        )}
      </main>

      <Footer scrollToSection={scrollToSection} />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Testimonial, Video } from '../../types';
import { Trash2, Plus, Image as ImageIcon, Type, LogOut, LayoutDashboard, Video as VideoIcon, Quote, Loader2, Sparkles } from 'lucide-react';
import { analyzeImageForTestimonial } from '../../services/geminiService';

interface DashboardProps {
    testimonials: Testimonial[];
    videos: Video[];
    onUpdateTestimonials: (items: Testimonial[]) => void;
    onUpdateVideos: (items: Video[]) => void;
    onLogout: () => void;
}

type Tab = 'testimonials' | 'videos';

const Dashboard: React.FC<DashboardProps> = ({ testimonials, videos, onUpdateTestimonials, onUpdateVideos, onLogout }) => {
    const [activeTab, setActiveTab] = useState<Tab>('testimonials');

    // Testimonial State
    const [newItemType, setNewItemType] = useState<'text' | 'image' | 'mixed'>('image');
    const [newAuthor, setNewAuthor] = useState('');
    const [newRole, setNewRole] = useState('');
    const [newContent, setNewContent] = useState('');
    const [newImage, setNewImage] = useState<string>('');
    const [isAnalyzing, setIsAnalyzing] = useState(false);

    // Video State
    const [videoUrl, setVideoUrl] = useState('');
    const [videoTitle, setVideoTitle] = useState('');

    // --- Helper: Compress Image to avoid LocalStorage Limits ---
    const compressImage = (base64Str: string, maxWidth = 800): Promise<string> => {
        return new Promise((resolve) => {
            const img = new Image();
            img.src = base64Str;
            img.onload = () => {
                const canvas = document.createElement('canvas');
                let width = img.width;
                let height = img.height;

                if (width > maxWidth) {
                    height *= maxWidth / width;
                    width = maxWidth;
                }

                canvas.width = width;
                canvas.height = height;
                const ctx = canvas.getContext('2d');
                ctx?.drawImage(img, 0, 0, width, height);
                // Reduce quality to 0.7 to save space
                resolve(canvas.toDataURL('image/jpeg', 0.7));
            };
        });
    };

    const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = async () => {
                const rawBase64 = reader.result as string;

                // 1. Compress Image immediately
                const compressedBase64 = await compressImage(rawBase64);
                setNewImage(compressedBase64);

                // 2. Start AI Analysis on the compressed image
                setIsAnalyzing(true);
                try {
                    const analysis = await analyzeImageForTestimonial(compressedBase64);
                    if (analysis.content || analysis.author) {
                        setNewContent(analysis.content || '');
                        setNewAuthor(analysis.author || 'غير معروف');
                        setNewRole(analysis.role || '');
                        setNewItemType('mixed');
                    }
                } catch (error) {
                    console.error("Failed to analyze image", error);
                } finally {
                    setIsAnalyzing(false);
                }
            };
            reader.readAsDataURL(file);
        }
    };

    const handleDeleteTestimonial = (id: string | number) => {
        if (window.confirm('هل أنت متأكد من حذف هذا العنصر؟')) {
            onUpdateTestimonials(testimonials.filter(item => item.id !== id));
        }
    };

    const handleDeleteVideo = (id: string) => {
        if (window.confirm('هل أنت متأكد من حذف هذا الفيديو؟')) {
            onUpdateVideos(videos.filter(item => item.id !== id));
        }
    };

    const handleAddTestimonial = (e: React.FormEvent) => {
        e.preventDefault();
        const newItem: Testimonial = {
            id: Date.now(),
            type: newItemType,
            author: (newItemType === 'text' || newItemType === 'mixed') ? newAuthor : undefined,
            role: (newItemType === 'text' || newItemType === 'mixed') ? newRole : undefined,
            content: (newItemType === 'text' || newItemType === 'mixed') ? newContent : undefined,
            src: (newItemType === 'image' || newItemType === 'mixed') ? newImage : undefined
        };
        onUpdateTestimonials([newItem, ...testimonials]);

        // Reset form
        setNewAuthor(''); 
        setNewRole(''); 
        setNewContent(''); 
        setNewImage('');
        setNewItemType('image'); 

        alert('تم الحفظ بنجاح! سيظهر العنصر في الموقع فوراً.');
    };

    const handleAddVideo = (e: React.FormEvent) => {
        e.preventDefault();

        let videoId = '';
        try {
            if (videoUrl.includes('v=')) {
                videoId = videoUrl.split('v=')[1].split('&')[0];
            } else if (videoUrl.includes('youtu.be/')) {
                videoId = videoUrl.split('youtu.be/')[1].split('?')[0];
            } else if (videoUrl.includes('shorts/')) {
                 videoId = videoUrl.split('shorts/')[1].split('?')[0];
            }
        } catch (e) {
            alert('الرابط غير صحيح');
            return;
        }

        if (!videoId) {
            alert('لم يتم التعرف على معرف الفيديو. تأكد من الرابط (YouTube Link).');
            return;
        }

        const newVideo: Video = {
            id: videoId,
            title: videoTitle,
            url: videoUrl,
            thumbnail: `https://i.ytimg.com/vi/${videoId}/hqdefault.jpg`,
            date: new Date().toLocaleDateString('ar-EG'),
            views: 'جديد'
        };

        onUpdateVideos([newVideo, ...videos]);
        setVideoUrl('');
        setVideoTitle('');
        alert('تم حفظ الفيديو بنجاح!');
    };

    return (
        <div className="min-h-screen bg-gray-100 flex flex-col">
            {/* Top Bar */}
            <div className="bg-slate-900 text-white p-4 shadow-md flex justify-between items-center sticky top-0 z-50">
                <div className="flex items-center gap-3">
                    <LayoutDashboard className="text-gold-500" />
                    <div>
                        <h1 className="font-heading font-bold text-xl">لوحة التحكم</h1>
                        <p className="text-[10px] text-gray-400">قاعدة البيانات المحلية مفعلة</p>
                    </div>
                </div>
                <button 
                    onClick={onLogout}
                    className="flex items-center gap-2 text-sm bg-slate-800 hover:bg-slate-700 px-4 py-2 rounded-lg transition-colors"
                >
                    <LogOut size={16} />
                    خروج
                </button>
            </div>

            <div className="container mx-auto p-4 md:p-6">

                {/* Tabs */}
                <div className="flex gap-4 mb-8 bg-white p-2 rounded-xl shadow-sm max-w-md">
                    <button 
                        onClick={() => setActiveTab('testimonials')}
                        className={`flex-1 py-3 rounded-lg font-bold flex items-center justify-center gap-2 transition-all ${activeTab === 'testimonials' ? 'bg-slate-900 text-white shadow' : 'text-gray-500 hover:bg-gray-50'}`}
                    >
                        <Quote size={20} />
                        الآراء والصور
                    </button>
                    <button 
                        onClick={() => setActiveTab('videos')}
                        className={`flex-1 py-3 rounded-lg font-bold flex items-center justify-center gap-2 transition-all ${activeTab === 'videos' ? 'bg-red-600 text-white shadow' : 'text-gray-500 hover:bg-gray-50'}`}
                    >
                        <VideoIcon size={20} />
                        الفيديوهات
                    </button>
                </div>

                <div className="grid lg:grid-cols-3 gap-8">
                    {/* Input Form */}
                    <div className="lg:col-span-1">
                        <div className="bg-white p-6 rounded-xl shadow-md sticky top-24">
                            <h2 className="text-xl font-bold mb-6 border-b pb-2 flex items-center gap-2">
                                <Plus size={20} className={activeTab === 'videos' ? 'text-red-500' : 'text-gold-500'} />
                                {activeTab === 'testimonials' ? 'إضافة محتوى جديد' : 'إضافة فيديو جديد'}
                            </h2>

                            {activeTab === 'testimonials' ? (
                                <form onSubmit={handleAddTestimonial} className="space-y-4">
                                    <div className="flex gap-2 p-1 bg-gray-100 rounded-lg mb-4">
                                        <button type="button" onClick={() => setNewItemType('image')} className={`flex-1 py-2 text-sm font-bold rounded-md flex items-center justify-center gap-2 transition-all ${newItemType === 'image' ? 'bg-white shadow text-blue-600' : 'text-gray-500'}`}>
                                            <ImageIcon size={16} /> صورة
                                        </button>
                                        <button type="button" onClick={() => setNewItemType('text')} className={`flex-1 py-2 text-sm font-bold rounded-md flex items-center justify-center gap-2 transition-all ${newItemType === 'text' ? 'bg-white shadow text-blue-600' : 'text-gray-500'}`}>
                                            <Type size={16} /> نص
                                        </button>
                                        <button type="button" onClick={() => setNewItemType('mixed')} className={`flex-1 py-2 text-sm font-bold rounded-md flex items-center justify-center gap-2 transition-all ${newItemType === 'mixed' ? 'bg-white shadow text-purple-600' : 'text-gray-500'}`}>
                                            <Sparkles size={16} /> ذكي
