import { Testimonial, Video } from '../types';
import { initializeApp } from 'firebase/app';
import { getFirestore, collection, getDocs, doc, setDoc, deleteDoc, query, orderBy } from 'firebase/firestore';

const KEYS = {
  TESTIMONIALS: 'gamil_testimonials',
  VIDEOS: 'gamil_videos',
  FIREBASE_CONFIG: 'gamil_firebase_config'
};

// Default Data (Used only if database is empty/fresh)
export const INITIAL_VIDEOS: Video[] = [];
export const INITIAL_TESTIMONIALS: Testimonial[] = [
    { id: 1, type: 'text', content: "جميل عزالدين ليس مجرد إعلامي، بل هو جبهة إعلامية بحد ذاته.", author: "د. محمد العامري", role: "مستشار رئاسي" },
    { id: 2, type: 'text', content: "الروح الوطنية التي يتمتع بها العميد جميل عزالدين تلهمنا جميعاً.", author: "ناشط سياسي", role: "تويتر" },
];

// Interface for Firebase Configuration
export interface FirebaseConfig {
  apiKey: string;
  authDomain: string;
  projectId: string;
  storageBucket: string;
  messagingSenderId: string;
  appId: string;
}

let db: any = null;

// Initialize Firebase if config exists
const initFirebase = () => {
  if (typeof window === 'undefined') return;
  const configStr = localStorage.getItem(KEYS.FIREBASE_CONFIG);
  if (configStr) {
    try {
      const config = JSON.parse(configStr);
      // Prevent re-initialization error
      try {
        const app = initializeApp(config);
        db = getFirestore(app);
        console.log("🔥 Firebase Connected Successfully");
      } catch (e: any) {
        if (e.code === 'app/duplicate-app') {
           // If app already exists, just get Firestore (simple workaround for HMR)
           // In production this might need more robust handling, but fine for this scope.
        }
      }
    } catch (e) {
      console.error("Invalid Firebase Config", e);
    }
  }
};

// Initialize on load
initFirebase();

export const StorageService = {
  isCloudEnabled: (): boolean => {
    return !!localStorage.getItem(KEYS.FIREBASE_CONFIG);
  },

  saveFirebaseConfig: (config: FirebaseConfig) => {
    localStorage.setItem(KEYS.FIREBASE_CONFIG, JSON.stringify(config));
    window.location.reload(); // Reload to initialize Firebase
  },

  clearFirebaseConfig: () => {
    localStorage.removeItem(KEYS.FIREBASE_CONFIG);
    window.location.reload();
  },

  // --- Testimonials Operations ---
  getTestimonials: async (): Promise<Testimonial[]> => {
    // 1. Try Firebase
    if (db) {
      try {
        const q = query(collection(db, 'testimonials'), orderBy('id', 'desc'));
        const querySnapshot = await getDocs(q);
        const items: Testimonial[] = [];
        querySnapshot.forEach((doc) => {
          items.push(doc.data() as Testimonial);
        });
        if (items.length > 0) return items;
      } catch (error) {
        console.error("Firebase Error (Testimonials):", error);
        // Fallback or Alert?
      }
    }

    // 2. Fallback to LocalStorage
    try {
      const data = localStorage.getItem(KEYS.TESTIMONIALS);
      return data ? JSON.parse(data) : INITIAL_TESTIMONIALS;
    } catch (error) {
      return INITIAL_TESTIMONIALS;
    }
  },

  saveTestimonials: async (items: Testimonial[]): Promise<boolean> => {
    // Save to Cloud
    if (db) {
      try {
        // Warning: This is a simple sync (overwrite logic simulated). 
        // For a real app, we should add/update specific docs. 
        // To keep it simple with the current array-based logic:
        // We will loop and setDoc.
        for (const item of items) {
           await setDoc(doc(db, 'testimonials', String(item.id)), item);
        }

        // Also handling deletions is tricky in this "overwrite all" pattern without tracking.
        // But for this simplified scope, we mainly care about adding.
        // To allow deleting, we would need to know what was deleted.
        // A simpler approach for this demo:
        // We accept the UI state is truth.

      } catch (error) {
        console.error("Firebase Save Error:", error);
        alert("حدث خطأ في الاتصال بالسيرفر. تأكد من صلاحيات الكتابة.");
        return false;
      }
    }

    // Always save to LocalStorage as backup/cache
    try {
      localStorage.setItem(KEYS.TESTIMONIALS, JSON.stringify(items));
      return true;
    } catch (error: any) {
      if (error.name === 'QuotaExceededError') {
         // Quota error handling
      }
      return false;
    }
  },

  deleteTestimonial: async (id: string | number): Promise<void> => {
      if (db) {
          try {
              await deleteDoc(doc(db, 'testimonials', String(id)));
          } catch(e) { console.error(e); }
      }
      // We also update local storage in the UI handler usually, 
      // but the UI calls saveTestimonials with the new array anyway.
  },

  // --- Videos Operations ---
  getVideos: async (): Promise<Video[]> => {
    if (db) {
      try {
        const q = query(collection(db, 'videos'), orderBy('date', 'desc'));
        const querySnapshot = await getDocs(q);
        const items: Video[] = [];
        querySnapshot.forEach((doc) => {
          items.push(doc.data() as Video);
        });
        if (items.length > 0) return items;
      } catch (error) {
        console.error("Firebase Error (Videos):", error);
      }
    }

    try {
      const data = localStorage.getItem(KEYS.VIDEOS);
      return data ? JSON.parse(data) : INITIAL_VIDEOS;
    } catch (error) {
      return INITIAL_VIDEOS;
    }
  },

  saveVideos: async (items: Video[]): Promise<boolean> => {
    if (db) {
      try {
        for (const item of items) {
            await setDoc(doc(db, 'videos', item.id), item);
        }
      } catch (error) {
        console.error("Firebase Video Save Error:", error);
        return false;
      }
    }

    try {
      localStorage.setItem(KEYS.VIDEOS, JSON.stringify(items));
      return true;
    } catch (error) {
      return false;
    }
  },

  deleteVideo: async (id: string): Promise<void> => {
    if (db) {
        try {
            await deleteDoc(doc(db, 'videos', id));
        } catch(e) { console.error(e); }
    }
  }
};

import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import Hero from './components/Hero';
import AboutSection from './components/AboutSection';
import YouTubeSlider from './components/YouTubeSlider';
import TwitterCard from './components/TwitterCard';
import FacebookSection from './components/FacebookSection';
import Testimonials from './components/Testimonials';
import Footer from './components/Footer';
import ArticlesPage from './components/ArticlesPage';
import LoginPage from './components/admin/LoginPage';
import Dashboard from './components/admin/Dashboard';
import { Section, AppView, Testimonial, Video } from './types';
import { StorageService } from './services/storage';
import { Loader2 } from 'lucide-react';

const App: React.FC = () => {
  const [activeSection, setActiveSection] = useState<Section>(Section.HOME);
  const [currentView, setCurrentView] = useState<AppView>('home');
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  const [testimonials, setTestimonials] = useState<Testimonial[]>([]);
  const [videos, setVideos] = useState<Video[]>([]);

  // Async Data Loading
  useEffect(() => {
      const loadData = async () => {
          setIsLoading(true);
          try {
              const tData = await StorageService.getTestimonials();
              const vData = await StorageService.getVideos();
              setTestimonials(tData);
              setVideos(vData);
          } catch (e) {
              console.error("Failed to load data", e);
          } finally {
              setIsLoading(false);
          }
      };
      loadData();
  }, []);

  // Handle Routing
  useEffect(() => {
    const handleRouteCheck = () => {
      const path = window.location.pathname;
      const hash = window.location.hash;

      if (path === '/login' || hash === '#login') {
        setCurrentView('login');
      } else if (hash === '#dashboard') {
        setCurrentView('dashboard');
      } else if (hash === '#articles') {
        setCurrentView('articles');
      } else {
        if (path === '/' && !hash) setCurrentView('home');

        if (hash.startsWith('#section-')) {
            const sectionId = hash.replace('#section-', '') as Section;
            if (currentView !== 'home') {
                setCurrentView('home');
                setTimeout(() => {
                    const element = document.getElementById(sectionId);
                    if (element) element.scrollIntoView({ behavior: 'smooth' });
                }, 100);
            } else {
                 const element = document.getElementById(sectionId);
                 if (element) element.scrollIntoView({ behavior: 'smooth' });
            }
        }
      }
    };

    handleRouteCheck();
    window.addEventListener('popstate', handleRouteCheck);
    window.addEventListener('hashchange', handleRouteCheck);
    return () => {
        window.removeEventListener('popstate', handleRouteCheck);
        window.removeEventListener('hashchange', handleRouteCheck);
    };
  }, [currentView]);

  // Handle Database Updates
  const handleUpdateTestimonials = async (newItems: Testimonial[]) => {
      setTestimonials(newItems);
      await StorageService.saveTestimonials(newItems);
  };

  const handleUpdateVideos = async (newVideos: Video[]) => {
      setVideos(newVideos);
      await StorageService.saveVideos(newVideos);
  };

  const scrollToSection = (sectionId: Section) => {
    if (currentView !== 'home') {
        setCurrentView('home');
        setTimeout(() => {
             const element = document.getElementById(sectionId);
             if (element) element.scrollIntoView({ behavior: 'smooth' });
             history.pushState(null, '', `/#section-${sectionId}`);
        }, 50);
    } else {
        const element = document.getElementById(sectionId);
        if (element) {
            element.scrollIntoView({ behavior: 'smooth' });
        }
        history.pushState(null, '', `/#section-${sectionId}`);
    }
    setActiveSection(sectionId);
  };

  const navigateHome = () => {
      history.pushState(null, '', '/');
      setCurrentView('home');
      window.scrollTo({ top: 0, behavior: 'smooth' });
  }

  const handleLogin = (success: boolean) => {
      if (success) {
          setIsAuthenticated(true);
          window.location.hash = '#dashboard';
          setCurrentView('dashboard');
      }
  };

  const handleLogout = () => {
      setIsAuthenticated(false);
      navigateHome();
  };

  if (isLoading) {
      return (
          <div className="min-h-screen flex flex-col items-center justify-center bg-slate-900 text-white gap-4">
              <Loader2 className="w-12 h-12 text-gold-500 animate-spin" />
              <p className="font-heading animate-pulse">جاري الاتصال بالسيرفر...</p>
          </div>
      );
  }

  if (currentView === 'login') {
      return <LoginPage onLogin={handleLogin} />;
  }

  if (currentView === 'dashboard') {
      if (!isAuthenticated) return <LoginPage onLogin={handleLogin} />;
      return (
        <Dashboard 
            testimonials={testimonials} 
            videos={videos}
            onUpdateTestimonials={handleUpdateTestimonials} 
            onUpdateVideos={handleUpdateVideos}
            onLogout={handleLogout} 
        />
      );
  }

  return (
    <div className="font-sans text-slate-900 bg-white min-h-screen">
      <Header 
        activeSection={activeSection} 
        activeView={currentView}
        scrollToSection={scrollToSection} 
        onNavigateHome={navigateHome}
      />

      <main>
        {currentView === 'home' ? (
            <>
                <Hero scrollToSection={scrollToSection} />
                <AboutSection onNavigateToArticles={() => { window.location.hash = '#articles'; setCurrentView('articles'); }} />
                <YouTubeSlider videos={videos} />
                <TwitterCard />
                <FacebookSection />
                <Testimonials items={testimonials} />
            </>
        ) : (
            <ArticlesPage onBack={navigateHome} />
        )}
      </main>

      <Footer scrollToSection={scrollToSection} />
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Testimonial, Video } from '../../types';
import { Trash2, Plus, Image as ImageIcon, Type, LogOut, LayoutDashboard, Video as VideoIcon, Quote, Loader2, Sparkles, Settings, Cloud, CloudOff, Save } from 'lucide-react';
import { analyzeImageForTestimonial } from '../../services/geminiService';
import { StorageService, FirebaseConfig } from '../../services/storage';

interface DashboardProps {
    testimonials: Testimonial[];
    videos: Video[];
    onUpdateTestimonials: (items: Testimonial[]) => void;
    onUpdateVideos: (items: Video[]) => void;
    onLogout: () => void;
}

type Tab = 'testimonials' | 'videos' | 'settings';

const Dashboard: React.FC<DashboardProps> = ({ testimonials, videos, onUpdateTestimonials, onUpdateVideos, onLogout }) => {
    const [activeTab, setActiveTab] = useState<Tab>('testimonials');
    const [isCloud, setIsCloud] = useState(false);

    // Settings State
    const [fbConfig, setFbConfig] = useState<string>('');

    // Testimonial State
    const [newItemType, setNewItemType] = useState<'text' | 'image' | 'mixed'>('image');
    const [newAuthor, setNewAuthor] = useState('');
    const [newRole, setNewRole] = useState('');
    const [newContent, setNewContent] = useState('');
    const [newImage, setNewImage] = useState<string>('');
    const [isAnalyzing, setIsAnalyzing] = useState(false);

    // Video State
    const [videoUrl, setVideoUrl] = useState('');
    const [videoTitle, setVideoTitle] = useState('');

    useEffect(() => {
        setIsCloud(StorageService.isCloudEnabled());
    }, []);

    const handleSaveSettings = () => {
        try {
            const config = JSON.parse(fbConfig);
            StorageService.saveFirebaseConfig(config);
        } catch (e) {
            alert("صيغة JSON غير صحيحة. تأكد من نسخ الإعدادات بشكل صحيح من Firebase.");
        }
    };

    const handleDisconnect = () => {
        if(window.confirm('هل أنت متأكد؟ سيعود الموقع للعمل محلياً فقط.')) {
            StorageService.clearFirebaseConfig();
        }
    };

    // --- Helper: Compress Image to avoid Limits ---
    const compressImage = (base64Str: string, maxWidth = 800): Promise<string> => {
        return new Promise((resolve) => {
            const img = new Image();
            img.src = base64Str;
            img.onload = () => {
                const canvas = document.createElement('canvas');
                let width = img.width;
                let height = img.height;

                if (width > maxWidth) {
                    height *= maxWidth / width;
                    width = maxWidth;
                }

                canvas.width = width;
                canvas.height = height;
                const ctx = canvas.getContext('2d');
                ctx?.drawImage(img, 0, 0, width, height);
                // Reduce quality to 0.7 to save space
                resolve(canvas.toDataURL('image/jpeg', 0.7));
            };
        });
    };

    const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = async () => {
                const rawBase64 = reader.result as string;

                // 1. Compress Image
                const compressedBase64 = await compressImage(rawBase64);
                setNewImage(compressedBase64);

                // 2. Start AI Analysis
                setIsAnalyzing(true);
                try {
                    const analysis = await analyzeImageForTestimonial(compressedBase64);
                    if (analysis.content || analysis.author) {
                        setNewContent(analysis.content || '');
                        setNewAuthor(analysis.author || 'غير معروف');
                        setNewRole(analysis.role || '');
                        setNewItemType('mixed');
                    }
                } catch (error) {
                    console.error("Failed to analyze image", error);
                } finally {
                    setIsAnalyzing(false);
                }
            };
            reader.readAsDataURL(file);
        }
    };

    const handleDeleteTestimonial = (id: string | number) => {
        if (window.confirm('هل أنت متأكد من حذف هذا العنصر؟')) {
            const updated = testimonials.filter(item => item.id !== id);
            onUpdateTestimonials(updated);
            StorageService.deleteTestimonial(id);
        }
    };

    const handleDeleteVideo = (id: string) => {
        if (window.confirm('هل أنت متأكد من حذف هذا الفيديو؟')) {
            const updated = videos.filter(item => item.id !== id);
            onUpdateVideos(updated);
            StorageService.deleteVideo(id);
        }
    };

    const handleAddTestimonial = (e: React.FormEvent) => {
        e.preventDefault();
        const newItem: Testimonial = {
            id: Date.now(),
            type: newItemType,
            author: (newItemType === 'text' || newItemType === 'mixed') ? newAuthor : undefined,
            role: (newItemType === 'text' || newItemType === 'mixed') ? newRole : undefined,
            content: (newItemType === 'text' || newItemType === 'mixed') ? newContent : undefined,
            src: (newItemType === 'image' || newItemType === 'mixed') ? newImage : undefined
        };
        onUpdateTestimonials([newItem, ...testimonials]); // Adds to local state immediately

