import { Testimonial, Video } from '../types';
import { initializeApp } from 'firebase/app';
import { getFirestore, collection, getDocs, doc, setDoc, deleteDoc, query, orderBy, getDoc } from 'firebase/firestore';

const KEYS = {
  TESTIMONIALS: 'gamil_testimonials',
  VIDEOS: 'gamil_videos',
  FIREBASE_CONFIG: 'gamil_firebase_config',
  CHANNEL_ID: 'gamil_channel_id'
};

// Default Data (Used only if database is empty/fresh)
export const INITIAL_VIDEOS: Video[] = [];
export const INITIAL_TESTIMONIALS: Testimonial[] = [
    { id: 1, type: 'text', content: "جميل عزالدين ليس مجرد إعلامي، بل هو جبهة إعلامية بحد ذاته.", author: "د. محمد العامري", role: "مستشار رئاسي" },
    { id: 2, type: 'text', content: "الروح الوطنية التي يتمتع بها العميد جميل عزالدين تلهمنا جميعاً.", author: "ناشط سياسي", role: "تويتر" },
];

// Interface for Firebase Configuration
export interface FirebaseConfig {
  apiKey: string;
  authDomain: string;
  projectId: string;
  storageBucket: string;
  messagingSenderId: string;
  appId: string;
}

let db: any = null;

// Initialize Firebase if config exists
const initFirebase = () => {
  if (typeof window === 'undefined') return;
  const configStr = localStorage.getItem(KEYS.FIREBASE_CONFIG);
  if (configStr) {
    try {
      const config = JSON.parse(configStr);
      // Prevent re-initialization error
      try {
        const app = initializeApp(config);
        db = getFirestore(app);
        console.log("🔥 Firebase Connected Successfully");
      } catch (e: any) {
        if (e.code === 'app/duplicate-app') {
           // If app already exists, just get Firestore (simple workaround for HMR)
        }
      }
    } catch (e) {
      console.error("Invalid Firebase Config", e);
    }
  }
};

// Initialize on load
initFirebase();

const fetchVideosFromRSS = async (channelId: string): Promise<Video[]> => {
    try {
        const rssUrl = `https://www.youtube.com/feeds/videos.xml?channel_id=${channelId}`;
        const apiUrl = `https://api.rss2json.com/v1/api.json?rss_url=${encodeURIComponent(rssUrl)}`;

        const response = await fetch(apiUrl);
        const data = await response.json();

        if (data.status === 'ok' && data.items) {
            return data.items.map((item: any) => {
                // Extract Video ID from link or guid
                const videoId = item.guid.split(':')[2] || item.link.split('v=')[1];
                return {
                    id: videoId,
                    title: item.title,
                    thumbnail: `https://i.ytimg.com/vi/${videoId}/hqdefault.jpg`, // RSS thumbnail is sometimes low res
                    url: item.link,
                    views: 'مشاهدة', // RSS doesn't provide view count
                    date: new Date(item.pubDate).toLocaleDateString('ar-EG')
                };
            });
        }
        return [];
    } catch (error) {
        console.error("Failed to fetch RSS videos:", error);
        return [];
    }
};

export const StorageService = {
  isCloudEnabled: (): boolean => {
    return !!localStorage.getItem(KEYS.FIREBASE_CONFIG);
  },

  saveFirebaseConfig: (config: FirebaseConfig) => {
    localStorage.setItem(KEYS.FIREBASE_CONFIG, JSON.stringify(config));
    window.location.reload(); // Reload to initialize Firebase
  },

  clearFirebaseConfig: () => {
    localStorage.removeItem(KEYS.FIREBASE_CONFIG);
    window.location.reload();
  },

  // --- Settings Operations ---
  getChannelId: async (): Promise<string> => {
      if (db) {
          try {
              const docRef = doc(db, 'settings', 'general');
              const docSnap = await getDoc(docRef);
              if (docSnap.exists()) {
                  return docSnap.data().channelId || '';
              }
          } catch (e) { console.error(e); }
      }
      return localStorage.getItem(KEYS.CHANNEL_ID) || '';
  },

  saveChannelId: async (channelId: string): Promise<void> => {
      localStorage.setItem(KEYS.CHANNEL_ID, channelId);
      if (db) {
          try {
              await setDoc(doc(db, 'settings', 'general'), { channelId }, { merge: true });
          } catch (e) { console.error("Firebase save settings error", e); }
      }
  },

  // --- Testimonials Operations ---
  getTestimonials: async (): Promise<Testimonial[]> => {
    // 1. Try Firebase
    if (db) {
      try {
        const q = query(collection(db, 'testimonials'), orderBy('id', 'desc'));
        const querySnapshot = await getDocs(q);
        const items: Testimonial[] = [];
        querySnapshot.forEach((doc) => {
          items.push(doc.data() as Testimonial);
        });
        if (items.length > 0) return items;
      } catch (error) {
        console.error("Firebase Error (Testimonials):", error);
      }
    }

    // 2. Fallback to LocalStorage
    try {
      const data = localStorage.getItem(KEYS.TESTIMONIALS);
      return data ? JSON.parse(data) : INITIAL_TESTIMONIALS;
    } catch (error) {
      return INITIAL_TESTIMONIALS;
    }
  },

  saveTestimonials: async (items: Testimonial[]): Promise<boolean> => {
    if (db) {
      try {
        for (const item of items) {
           await setDoc(doc(db, 'testimonials', String(item.id)), item);
        }
      } catch (error) {
        console.error("Firebase Save Error:", error);
        alert("حدث خطأ في الاتصال بالسيرفر. تأكد من صلاحيات الكتابة.");
        return false;
      }
    }

    try {
      localStorage.setItem(KEYS.TESTIMONIALS, JSON.stringify(items));
      return true;
    } catch (error: any) {
      return false;
    }
  },

  deleteTestimonial: async (id: string | number): Promise<void> => {
      if (db) {
          try {
              await deleteDoc(doc(db, 'testimonials', String(id)));
          } catch(e) { console.error(e); }
      }
  },

  // --- Videos Operations ---
  getVideos: async (): Promise<Video[]> => {
    // 1. Check if Channel ID is set
    const channelId = await StorageService.getChannelId();
    if (channelId) {
        const rssVideos = await fetchVideosFromRSS(channelId);
        if (rssVideos.length > 0) return rssVideos;
    }

    // 2. Fallback to manual DB list
    if (db) {
      try {
        const q = query(collection(db, 'videos'), orderBy('date', 'desc'));
        const querySnapshot = await getDocs(q);
        const items: Video[] = [];
        querySnapshot.forEach((doc) => {
          items.push(doc.data() as Video);
        });
        if (items.length > 0) return items;
      } catch (error) {
        console.error("Firebase Error (Videos):", error);
      }
    }

    try {
      const data = localStorage.getItem(KEYS.VIDEOS);
      return data ? JSON.parse(data) : INITIAL_VIDEOS;
    } catch (error) {
      return INITIAL_VIDEOS;
    }
  },

  saveVideos: async (items: Video[]): Promise<boolean> => {
    if (db) {
      try {
        for (const item of items) {
            await setDoc(doc(db, 'videos', item.id), item);
        }
      } catch (error) {
        console.error("Firebase Video Save Error:", error);
        return false;
      }
    }

    try {
      localStorage.setItem(KEYS.VIDEOS, JSON.stringify(items));
      return true;
    } catch (error) {
      return false;
    }
  },

  deleteVideo: async (id: string): Promise<void> => {
    if (db) {
        try {
            await deleteDoc(doc(db, 'videos', id));
        } catch(e) { console.error(e); }
    }
  }
};

import React, { useState, useEffect } from 'react';
import { Testimonial, Video } from '../../types';
import { Trash2, Plus, Image as ImageIcon, Type, LogOut, LayoutDashboard, Video as VideoIcon, Quote, Loader2, Sparkles, Settings, Cloud, CloudOff, Save, Youtube, RefreshCw } from 'lucide-react';
import { analyzeImageForTestimonial } from '../../services/geminiService';
import { StorageService } from '../../services/storage';

interface DashboardProps {
    testimonials: Testimonial[];
    videos: Video[];
    onUpdateTestimonials: (items: Testimonial[]) => void;
    onUpdateVideos: (items: Video[]) => void;
    onLogout: () => void;
}

type Tab = 'testimonials' | 'videos' | 'settings';

const Dashboard: React.FC<DashboardProps> = ({ testimonials, videos, onUpdateTestimonials, onUpdateVideos, onLogout }) => {
    const [activeTab, setActiveTab] = useState<Tab>('testimonials');
    const [isCloud, setIsCloud] = useState(false);

    // Settings State
    const [fbConfig, setFbConfig] = useState<string>('');

    // Testimonial State
    const [newItemType, setNewItemType] = useState<'text' | 'image' | 'mixed'>('image');
    const [newAuthor, setNewAuthor] = useState('');
    const [newRole, setNewRole] = useState('');
    const [newContent, setNewContent] = useState('');
    const [newImage, setNewImage] = useState<string>('');
    const [isAnalyzing, setIsAnalyzing] = useState(false);

    // Video State
    const [videoMode, setVideoMode] = useState<'manual' | 'channel'>('manual');
    const [channelId, setChannelId] = useState('');
    const [videoUrl, setVideoUrl] = useState('');
    const [videoTitle, setVideoTitle] = useState('');

    useEffect(() => {
        setIsCloud(StorageService.isCloudEnabled());

        // Load stored channel ID
        StorageService.getChannelId().then(id => {
            if (id) {
                setChannelId(id);
                setVideoMode('channel');
            }
        });
    }, []);

    const handleSaveSettings = () => {
        let configStr = fbConfig.trim();
        let config = null;

        try {
            config = JSON.parse(configStr);
        } catch (e) {
            try {
                const extractedConfig: any = {};
                const keys = ['apiKey', 'authDomain', 'projectId', 'storageBucket', 'messagingSenderId', 'appId', 'measurementId'];
                let found = false;

                keys.forEach(key => {
                    const regex = new RegExp(`\\b${key}\\s*:\\s*["']([^"']+)["']`);
                    const match = configStr.match(regex);
                    if (match) {
                        extractedConfig[key] = match[1];
                        found = true;
                    }
                });

                if (found && extractedConfig.apiKey) {
                    config = extractedConfig;
                }
            } catch (err) {
                console.error("Parsing failed", err);
            }
        }

        if (config && config.apiKey) {
            StorageService.saveFirebaseConfig(config);
            alert("تم حفظ الإعدادات بنجاح! سيتم إعادة تحميل الصفحة الآن.");
        } else {
             alert("لم نتمكن من قراءة الإعدادات. يرجى التأكد من نسخ كود Firebase بشكل صحيح (سواء JSON أو JavaScript Code).");
        }
    };

    const handleDisconnect = () => {
        if(window.confirm('هل أنت متأكد؟ سيعود الموقع للعمل محلياً فقط.')) {
            StorageService.clearFirebaseConfig();
        }
    };

    const handleSaveChannelId = async () => {
        if (!channelId) return;
        await StorageService.saveChannelId(channelId);
        alert('تم حفظ معرف القناة بنجاح! سيتم جلب الفيديوهات تلقائياً عند زيارة الموقع.');
        window.location.reload();
    };

    const compressImage = (base64Str: string, maxWidth = 800): Promise<string> => {
        return new Promise((resolve) => {
            const img = new Image();
            img.src = base64Str;
            img.onload = () => {
                const canvas = document.createElement('canvas');
                let width = img.width;
                let height = img.height;

                if (width > maxWidth) {
                    height *= maxWidth / width;
                    width = maxWidth;
                }

                canvas.width = width;
                canvas.height = height;
                const ctx = canvas.getContext('2d');
                ctx?.drawImage(img, 0, 0, width, height);
                resolve(canvas.toDataURL('image/jpeg', 0.7));
            };
        });
    };

    const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = async () => {
                const rawBase64 = reader.result as string;
                const compressedBase64 = await compressImage(rawBase64);
                setNewImage(compressedBase64);

                setIsAnalyzing(true);
                try {
                    const analysis = await analyzeImageForTestimonial(compressedBase64);
                    if (analysis.content || analysis.author) {
                        setNewContent(analysis.content || '');
                        setNewAuthor(analysis.author || 'غير معروف');
                        setNewRole(analysis.role || '');
                        setNewItemType('mixed');
                    }
                } catch (error) {
                    console.error("Failed to analyze image", error);
                } finally {
                    setIsAnalyzing(false);
                }
            };
            reader.readAsDataURL(file);
        }
    };

