import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import Hero from './components/Hero';
import AboutSection from './components/AboutSection';
import YouTubeSlider from './components/YouTubeSlider';
import TwitterCard from './components/TwitterCard';
import FacebookSection from './components/FacebookSection';
import Testimonials from './components/Testimonials';
import Footer from './components/Footer';
import ArticlesPage from './components/ArticlesPage';
import LoginPage from './components/admin/LoginPage';
import Dashboard from './components/admin/Dashboard';
import { Section, AppView, Testimonial, Video, CareerMoment, Article } from './types';
import { StorageService } from './services/storage';
import { Loader2 } from 'lucide-react';

const App: React.FC = () => {
  const [activeSection, setActiveSection] = useState<Section>(Section.HOME);
  const [currentView, setCurrentView] = useState<AppView>('home');
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  const [testimonials, setTestimonials] = useState<Testimonial[]>([]);
  const [videos, setVideos] = useState<Video[]>([]);
  const [careerMoments, setCareerMoments] = useState<CareerMoment[]>([]);
  const [articles, setArticles] = useState<Article[]>([]);

  // Async Data Loading
  useEffect(() => {
      const loadData = async () => {
          setIsLoading(true);
          try {
              const tData = await StorageService.getTestimonials();
              const vData = await StorageService.getVideos();
              const cData = await StorageService.getCareerMoments();
              const aData = await StorageService.getArticles();
              setTestimonials(tData);
              setVideos(vData);
              setCareerMoments(cData);
              setArticles(aData);
          } catch (e) {
              console.error("Failed to load data", e);
          } finally {
              setIsLoading(false);
          }
      };
      loadData();
  }, []);

  // Handle Routing
  useEffect(() => {
    const handleRouteCheck = () => {
      const path = window.location.pathname;
      const hash = window.location.hash;

      if (path === '/login' || hash === '#login') {
        setCurrentView('login');
      } else if (hash === '#dashboard') {
        setCurrentView('dashboard');
      } else if (hash === '#articles') {
        setCurrentView('articles');
      } else {
        if (path === '/' && !hash) setCurrentView('home');

        if (hash.startsWith('#section-')) {
            const sectionId = hash.replace('#section-', '') as Section;
            if (currentView !== 'home') {
                setCurrentView('home');
                setTimeout(() => {
                    const element = document.getElementById(sectionId);
                    if (element) element.scrollIntoView({ behavior: 'smooth' });
                }, 100);
            } else {
                 const element = document.getElementById(sectionId);
                 if (element) element.scrollIntoView({ behavior: 'smooth' });
            }
        }
      }
    };

    handleRouteCheck();
    window.addEventListener('popstate', handleRouteCheck);
    window.addEventListener('hashchange', handleRouteCheck);
    return () => {
        window.removeEventListener('popstate', handleRouteCheck);
        window.removeEventListener('hashchange', handleRouteCheck);
    };
  }, [currentView]);

  // Handle Database Updates
  const handleUpdateTestimonials = async (newItems: Testimonial[]) => {
      setTestimonials(newItems);
      await StorageService.saveTestimonials(newItems);
  };

  const handleUpdateVideos = async (newVideos: Video[]) => {
      setVideos(newVideos);
      await StorageService.saveVideos(newVideos);
  };

  const handleUpdateCareerMoments = async (newMoments: CareerMoment[]) => {
      setCareerMoments(newMoments);
      await StorageService.saveCareerMoments(newMoments);
  };

  const handleUpdateArticles = async (newArticles: Article[]) => {
      setArticles(newArticles);
      await StorageService.saveArticles(newArticles);
  };

  const scrollToSection = (sectionId: Section) => {
    if (currentView !== 'home') {
        setCurrentView('home');
        setTimeout(() => {
             const element = document.getElementById(sectionId);
             if (element) element.scrollIntoView({ behavior: 'smooth' });
             history.pushState(null, '', `/#section-${sectionId}`);
        }, 50);
    } else {
        const element = document.getElementById(sectionId);
        if (element) {
            element.scrollIntoView({ behavior: 'smooth' });
        }
        history.pushState(null, '', `/#section-${sectionId}`);
    }
    setActiveSection(sectionId);
  };

  const navigateHome = () => {
      history.pushState(null, '', '/');
      setCurrentView('home');
      window.scrollTo({ top: 0, behavior: 'smooth' });
  }

  const handleLogin = (success: boolean) => {
      if (success) {
          setIsAuthenticated(true);
          window.location.hash = '#dashboard';
          setCurrentView('dashboard');
      }
  };

  const handleLogout = () => {
      setIsAuthenticated(false);
      navigateHome();
  };

  if (isLoading) {
      return (
          <div className="min-h-screen flex flex-col items-center justify-center bg-slate-900 text-white gap-4">
              <Loader2 className="w-12 h-12 text-gold-500 animate-spin" />
              <p className="font-heading animate-pulse">جاري الاتصال بالسيرفر...</p>
          </div>
      );
  }

  if (currentView === 'login') {
      return <LoginPage onLogin={handleLogin} />;
  }

  if (currentView === 'dashboard') {
      if (!isAuthenticated) return <LoginPage onLogin={handleLogin} />;
      return (
        <Dashboard 
            testimonials={testimonials} 
            videos={videos}
            careerMoments={careerMoments}
            articles={articles}
            onUpdateTestimonials={handleUpdateTestimonials} 
            onUpdateVideos={handleUpdateVideos}
            onUpdateCareerMoments={handleUpdateCareerMoments}
            onUpdateArticles={handleUpdateArticles}
            onLogout={handleLogout} 
        />
      );
  }

  return (
    <div className="font-sans text-slate-900 bg-white min-h-screen">
      <Header 
        activeSection={activeSection} 
        activeView={currentView}
        scrollToSection={scrollToSection} 
        onNavigateHome={navigateHome}
      />

      <main>
        {currentView === 'home' ? (
            <>
                <Hero scrollToSection={scrollToSection} />
                <AboutSection 
                    onNavigateToArticles={() => { window.location.hash = '#articles'; setCurrentView('articles'); }} 
                    careerMoments={careerMoments}
                />
                <YouTubeSlider videos={videos} />
                <TwitterCard />
                <FacebookSection />
                <Testimonials items={testimonials} />
            </>
        ) : (
            <ArticlesPage 
                articles={articles}
                onBack={navigateHome} 
            />
        )}
      </main>

      <Footer scrollToSection={scrollToSection} />
    </div>
  );
};

export default App;

