// Interface for Firebase Configuration
export interface FirebaseConfig {
  apiKey: string;
  authDomain: string;
  projectId: string;
  storageBucket: string;
  messagingSenderId: string;
  appId: string;
}

let db: any = null;

// Initialize Firebase if config exists
const initFirebase = () => {
  if (typeof window === 'undefined') return;
  const configStr = localStorage.getItem(KEYS.FIREBASE_CONFIG);
  if (configStr) {
    try {
      const config = JSON.parse(configStr);
      // Prevent re-initialization error
      try {
        const app = initializeApp(config);
        db = getFirestore(app);
        console.log("🔥 Firebase Connected Successfully");
      } catch (e: any) {
        if (e.code === 'app/duplicate-app') {
           // If app already exists, just get Firestore (simple workaround for HMR)
        }
      }
    } catch (e) {
      console.error("Invalid Firebase Config", e);
    }
  }
};

// Initialize on load
initFirebase();

const fetchVideosFromRSS = async (channelId: string): Promise<Video[]> => {
    try {
        const rssUrl = `https://www.youtube.com/feeds/videos.xml?channel_id=${channelId}`;
        const apiUrl = `https://api.rss2json.com/v1/api.json?rss_url=${encodeURIComponent(rssUrl)}`;

        const response = await fetch(apiUrl);
        const data = await response.json();

        if (data.status === 'ok' && data.items) {
            return data.items.map((item: any) => {
                // Extract Video ID from link or guid
                const videoId = item.guid.split(':')[2] || item.link.split('v=')[1];
                return {
                    id: videoId,
                    title: item.title,
                    thumbnail: `https://i.ytimg.com/vi/${videoId}/hqdefault.jpg`, // RSS thumbnail is sometimes low res
                    url: item.link,
                    views: 'مشاهدة', // RSS doesn't provide view count
                    date: new Date(item.pubDate).toLocaleDateString('ar-EG')
                };
            });
        }
        return [];
    } catch (error) {
        console.error("Failed to fetch RSS videos:", error);
        return [];
    }
};

export const StorageService = {
  isCloudEnabled: (): boolean => {
    return !!localStorage.getItem(KEYS.FIREBASE_CONFIG);
  },

  saveFirebaseConfig: (config: FirebaseConfig) => {
    localStorage.setItem(KEYS.FIREBASE_CONFIG, JSON.stringify(config));
    window.location.reload(); // Reload to initialize Firebase
  },

  clearFirebaseConfig: () => {
    localStorage.removeItem(KEYS.FIREBASE_CONFIG);
    window.location.reload();
  },

  // --- Settings Operations ---
  getChannelId: async (): Promise<string> => {
      if (db) {
          try {
              const docRef = doc(db, 'settings', 'general');
              const docSnap = await getDoc(docRef);
              if (docSnap.exists()) {
                  return docSnap.data().channelId || '';
              }
          } catch (e) { console.error(e); }
      }
      return localStorage.getItem(KEYS.CHANNEL_ID) || '';
  },

  saveChannelId: async (channelId: string): Promise<void> => {
      localStorage.setItem(KEYS.CHANNEL_ID, channelId);
      if (db) {
          try {
              await setDoc(doc(db, 'settings', 'general'), { channelId }, { merge: true });
          } catch (e) { console.error("Firebase save settings error", e); }
      }
  },

  // --- Testimonials Operations ---
  getTestimonials: async (): Promise<Testimonial[]> => {
    // 1. Try Firebase
    if (db) {
      try {
        const q = query(collection(db, 'testimonials'), orderBy('id', 'desc'));
        const querySnapshot = await getDocs(q);
        const items: Testimonial[] = [];
        querySnapshot.forEach((doc) => {
          items.push(doc.data() as Testimonial);
        });
        if (items.length > 0) return items;
      } catch (error) {
        console.error("Firebase Error (Testimonials):", error);
      }
    }

    // 2. Fallback to LocalStorage
    try {
      const data = localStorage.getItem(KEYS.TESTIMONIALS);
      return data ? JSON.parse(data) : INITIAL_TESTIMONIALS;
    } catch (error) {
      return INITIAL_TESTIMONIALS;
    }
  },

  saveTestimonials: async (items: Testimonial[]): Promise<boolean> => {
    if (db) {
      try {
        for (const item of items) {
           await setDoc(doc(db, 'testimonials', String(item.id)), item);
        }
      } catch (error) {
        console.error("Firebase Save Error:", error);
        alert("حدث خطأ في الاتصال بالسيرفر. تأكد من صلاحيات الكتابة.");
        return false;
      }
    }

    try {
      localStorage.setItem(KEYS.TESTIMONIALS, JSON.stringify(items));
      return true;
    } catch (error: any) {
      return false;
    }
  },

  deleteTestimonial: async (id: string | number): Promise<void> => {
      if (db) {
          try {
              await deleteDoc(doc(db, 'testimonials', String(id)));
          } catch(e) { console.error(e); }
      }
  },

  // --- Videos Operations ---
  getVideos: async (): Promise<Video[]> => {
    // 1. Check if Channel ID is set
    const channelId = await StorageService.getChannelId();
    if (channelId) {
        const rssVideos = await fetchVideosFromRSS(channelId);
        if (rssVideos.length > 0) return rssVideos;
    }

    // 2. Fallback to manual DB list
    if (db) {
      try {
        const q = query(collection(db, 'videos'), orderBy('date', 'desc'));
        const querySnapshot = await getDocs(q);
        const items: Video[] = [];
        querySnapshot.forEach((doc) => {
