        >
          {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </div>

      {/* Mobile Menu Overlay */}
      {isMobileMenuOpen && (
        <div className="md:hidden absolute top-full left-0 right-0 bg-slate-900 border-t border-slate-800 shadow-xl p-4 flex flex-col gap-4">
          {navItems.map((item) => (
            <button
              key={item.id}
              onClick={() => handleNavClick(item.id)}
              className="text-right text-white py-2 hover:text-gold-500 transition-colors border-b border-slate-800 last:border-0"
            >
              {item.label}
            </button>
          ))}
          <div className="flex justify-center gap-6 mt-4 pt-4 border-t border-slate-800">
             <a href="https://twitter.com/gamilaz1" className="text-gray-400 hover:text-[#1DA1F2]"><Twitter /></a>
             <a href="https://www.facebook.com/jamilez2015" className="text-gray-400 hover:text-[#4267B2]"><Facebook /></a>
             <a href="https://www.youtube.com/channel/UC6w3x_g5oIPabiTR4BOsGXw" className="text-gray-400 hover:text-[#FF0000]"><Youtube /></a>
          </div>
        </div>
      )}
    </header>
  );
};

export default Header;

import React, { useState, useEffect } from 'react';
import { Testimonial, Video, CareerMoment, Article, GalleryImage } from '../../types';
import { Trash2, Plus, Image as ImageIcon, Type, LogOut, LayoutDashboard, Video as VideoIcon, Quote, Loader2, Sparkles, Settings, Cloud, CloudOff, Save, Youtube, RefreshCw, UserCheck, Newspaper, Pencil, Link2, Wand2, Images, UploadCloud } from 'lucide-react';
import { analyzeImageForTestimonial, expandArticleContent } from '../../services/geminiService';
import { StorageService } from '../../services/storage';

interface DashboardProps {
    testimonials: Testimonial[];
    videos: Video[];
    careerMoments: CareerMoment[];
    articles: Article[];
    gallery: GalleryImage[];
    onUpdateTestimonials: (items: Testimonial[]) => void;
    onUpdateVideos: (items: Video[]) => void;
    onUpdateCareerMoments: (items: CareerMoment[]) => void;
    onUpdateArticles: (items: Article[]) => void;
    onUpdateGallery: (items: GalleryImage[]) => void;
    onLogout: () => void;
}

type Tab = 'testimonials' | 'videos' | 'about' | 'articles' | 'gallery' | 'settings';

const Dashboard: React.FC<DashboardProps> = ({ testimonials, videos, careerMoments, articles, gallery, onUpdateTestimonials, onUpdateVideos, onUpdateCareerMoments, onUpdateArticles, onUpdateGallery, onLogout }) => {
    const [activeTab, setActiveTab] = useState<Tab>('testimonials');
    const [isCloud, setIsCloud] = useState(false);

    // Settings State
    const [fbConfig, setFbConfig] = useState<string>('');

    // Testimonial State
    const [newItemType, setNewItemType] = useState<'text' | 'image' | 'mixed'>('image');
    const [newAuthor, setNewAuthor] = useState('');
    const [newRole, setNewRole] = useState('');
    const [newContent, setNewContent] = useState('');
    const [newImage, setNewImage] = useState<string>('');
    const [isAnalyzing, setIsAnalyzing] = useState(false);

    // Video State
    const [videoMode, setVideoMode] = useState<'manual' | 'channel'>('manual');
    const [channelId, setChannelId] = useState('');
    const [videoUrl, setVideoUrl] = useState('');
    const [videoTitle, setVideoTitle] = useState('');

    // Career Moment State
    const [momentImage, setMomentImage] = useState<string>('');
    const [momentLabel, setMomentLabel] = useState('');
    const [momentYear, setMomentYear] = useState('');

    // Article State
    const [editingArticleId, setEditingArticleId] = useState<string | null>(null);
    const [articleTitle, setArticleTitle] = useState('');
    const [articleCategory, setArticleCategory] = useState('');
    const [articleImage, setArticleImage] = useState<string>('');
    const [articleExcerpt, setArticleExcerpt] = useState('');
    const [articleContent, setArticleContent] = useState('');
    const [isExpanding, setIsExpanding] = useState(false);

    // Import State
    const [importUrl, setImportUrl] = useState('');
    const [isImporting, setIsImporting] = useState(false);

    // Gallery State
    const [isUploadingGallery, setIsUploadingGallery] = useState(false);

    useEffect(() => {
        setIsCloud(StorageService.isCloudEnabled());

        // Load stored channel ID
        StorageService.getChannelId().then(id => {
            if (id) {
                setChannelId(id);
                setVideoMode('channel');
            }
        });
    }, []);

    const handleSaveSettings = () => {
        let configStr = fbConfig.trim();
        let config = null;

        try {
            config = JSON.parse(configStr);
        } catch (e) {
            try {
                const extractedConfig: any = {};
                const keys = ['apiKey', 'authDomain', 'projectId', 'storageBucket', 'messagingSenderId', 'appId', 'measurementId'];
                let found = false;

                keys.forEach(key => {
                    const regex = new RegExp(`\\b${key}\\s*:\\s*["']([^"']+)["']`);
                    const match = configStr.match(regex);
                    if (match) {
                        extractedConfig[key] = match[1];
                        found = true;
                    }
                });

                if (found && extractedConfig.apiKey) {
                    config = extractedConfig;
                }
            } catch (err) {
                console.error("Parsing failed", err);
            }
        }

        if (config && config.apiKey) {
            StorageService.saveFirebaseConfig(config);
            alert("تم حفظ الإعدادات بنجاح! سيتم إعادة تحميل الصفحة الآن.");
        } else {
             alert("لم نتمكن من قراءة الإعدادات. يرجى التأكد من نسخ كود Firebase بشكل صحيح (سواء JSON أو JavaScript Code).");
        }
    };

    const handleDisconnect = () => {
        if(window.confirm('هل أنت متأكد؟ سيعود الموقع للعمل محلياً فقط.')) {
            StorageService.clearFirebaseConfig();
        }
    };

    const handleSaveChannelId = async () => {
        if (!channelId) return;
        await StorageService.saveChannelId(channelId);
        alert('تم حفظ معرف القناة بنجاح! سيتم جلب الفيديوهات تلقائياً عند زيارة الموقع.');
        window.location.reload();
    };

    const compressImage = (base64Str: string, maxWidth = 800): Promise<string> => {
        return new Promise((resolve) => {
            const img = new Image();
            img.src = base64Str;
            img.onload = () => {
                const canvas = document.createElement('canvas');
                let width = img.width;
                let height = img.height;

                if (width > maxWidth) {
                    height *= maxWidth / width;
                    width = maxWidth;
                }

                canvas.width = width;
                canvas.height = height;
                const ctx = canvas.getContext('2d');
                ctx?.drawImage(img, 0, 0, width, height);
                resolve(canvas.toDataURL('image/jpeg', 0.7));
            };
        });
    };

    const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>, setter: (val: string) => void, analyze = false) => {
        const file = e.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = async () => {
                const rawBase64 = reader.result as string;
                const compressedBase64 = await compressImage(rawBase64);
                setter(compressedBase64);

                if (analyze) {
                    setIsAnalyzing(true);
                    try {
                        const analysis = await analyzeImageForTestimonial(compressedBase64);
                        if (analysis.content || analysis.author) {
                            setNewContent(analysis.content || '');
                            setNewAuthor(analysis.author || 'غير معروف');
                            setNewRole(analysis.role || '');
                            setNewItemType('mixed');
                        }
                    } catch (error) {
                        console.error("Failed to analyze image", error);
                    } finally {
                        setIsAnalyzing(false);
                    }
                }
            };
            reader.readAsDataURL(file);
        }
    };

    const handleBulkImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const files = e.target.files;
        if (!files || files.length === 0) return;

        setIsUploadingGallery(true);
        const newImages: GalleryImage[] = [];

        try {
            const promises = Array.from(files).map((file) => {
                return new Promise<void>((resolve) => {
                    const reader = new FileReader();
                    reader.onloadend = async () => {
                        const rawBase64 = reader.result as string;
                        const compressedBase64 = await compressImage(rawBase64, 1000); // slightly better quality for gallery

                        newImages.push({
                            id: Date.now() + Math.random(),
                            src: compressedBase64,
                            date: new Date().getFullYear().toString()
                        });
                        resolve();
                    };
                    reader.readAsDataURL(file);
                });
            });

            await Promise.all(promises);

            // Merge with existing gallery
            const updatedGallery = [...newImages, ...gallery];
            onUpdateGallery(updatedGallery);
            alert(`تم رفع ${newImages.length} صورة بنجاح!`);
        } catch (error) {
            console.error("Bulk upload error", error);
            alert("حدث خطأ أثناء رفع الصور");
        } finally {
            setIsUploadingGallery(false);
            // Reset input
            if(e.target) e.target.value = '';
        }
    };

    const handleDeleteTestimonial = (id: string | number) => {
        if (window.confirm('هل أنت متأكد من حذف هذا العنصر؟')) {
            const updated = testimonials.filter(item => item.id !== id);
            onUpdateTestimonials(updated);
            StorageService.deleteTestimonial(id);
        }
    };

    const handleDeleteVideo = (id: string) => {
        if (window.confirm('هل أنت متأكد من حذف هذا الفيديو؟')) {
            const updated = videos.filter(item => item.id !== id);
            onUpdateVideos(updated);
            StorageService.deleteVideo(id);
        }
    };

    const handleDeleteMoment = (id: string | number) => {
        if (window.confirm('هل أنت متأكد من حذف هذه الصورة؟')) {
            const updated = careerMoments.filter(item => item.id !== id);
            onUpdateCareerMoments(updated);
            StorageService.deleteCareerMoment(id);
        }
    };

    const handleDeleteArticle = (id: string) => {
        if (window.confirm('هل أنت متأكد من حذف هذا المقال؟')) {
            const updated = articles.filter(item => item.id !== id);
            onUpdateArticles(updated);
            StorageService.deleteArticle(id);
        }
    };

    const handleDeleteGalleryImage = (id: string | number) => {
        if (window.confirm('هل أنت متأكد من حذف هذه الصورة؟')) {
            const updated = gallery.filter(item => item.id !== id);
            onUpdateGallery(updated);
            StorageService.deleteGalleryImage(id);
        }
    };

    const handleEditArticle = (article: Article) => {
        setEditingArticleId(article.id);
        setArticleTitle(article.title);
        setArticleCategory(article.category);
        setArticleImage(article.image);
        setArticleExcerpt(article.excerpt);

        let contentText = article.content;
        setArticleContent(contentText);

        const form = document.querySelector('form');
        if (form) form.scrollIntoView({ behavior: 'smooth' });
    };

    const resetArticleForm = () => {
        setEditingArticleId(null);
        setArticleTitle('');
        setArticleCategory('');
        setArticleImage('');
        setArticleExcerpt('');
        setArticleContent('');
        setImportUrl('');
    };

    const handleAddTestimonial = (e: React.FormEvent) => {
        e.preventDefault();
        const newItem: Testimonial = {
            id: Date.now(),
            type: newItemType,
            author: (newItemType === 'text' || newItemType === 'mixed') ? newAuthor : undefined,
            role: (newItemType === 'text' || newItemType === 'mixed') ? newRole : undefined,
            content: (newItemType === 'text' || newItemType === 'mixed') ? newContent : undefined,
            src: (newItemType === 'image' || newItemType === 'mixed') ? newImage : undefined
        };
        onUpdateTestimonials([newItem, ...testimonials]);
        setNewAuthor(''); 
        setNewRole(''); 
        setNewContent(''); 
        setNewImage('');
        setNewItemType('image'); 
        alert('تم الحفظ بنجاح! سيظهر العنصر في الموقع فوراً.');
    };

    const handleAddVideo = (e: React.FormEvent) => {
        e.preventDefault();

        let videoId = '';
        try {
            if (videoUrl.includes('v=')) {
                videoId = videoUrl.split('v=')[1].split('&')[0];
            } else if (videoUrl.includes('youtu.be/')) {
                videoId = videoUrl.split('youtu.be/')[1].split('?')[0];
            } else if (videoUrl.includes('shorts/')) {
                 videoId = videoUrl.split('shorts/')[1].split('?')[0];
            }
        } catch (e) {
            alert('الرابط غير صحيح');
            return;
        }

        if (!videoId) {
            alert('لم يتم التعرف على معرف الفيديو. تأكد من الرابط (YouTube Link).');
            return;
        }

        const newVideo: Video = {
            id: videoId,
            title: videoTitle,
            url: videoUrl,
            thumbnail: `https://i.ytimg.com/vi/${videoId}/hqdefault.jpg`,
            date: new Date().toLocaleDateString('ar-EG'),
            views: 'جديد'
        };

        onUpdateVideos([newVideo, ...videos]);
        setVideoUrl('');
        setVideoTitle('');
        alert('تم حفظ الفيديو بنجاح!');
    };

    const handleAddCareerMoment = (e: React.FormEvent) => {
        e.preventDefault();
        const newMoment: CareerMoment = {
            id: Date.now(),
            src: momentImage,
            label: momentLabel,
            year: momentYear
        };
        onUpdateCareerMoments([newMoment, ...careerMoments]);
        setMomentImage('');
        setMomentLabel('');
        setMomentYear('');
        alert('تمت إضافة الصورة بنجاح!');
    };

    const handleExpandArticle = async () => {
        if (!articleTitle) {
            alert('يرجى كتابة عنوان للمقال أولاً.');
            return;
        }

        setIsExpanding(true);
        try {
            const brief = articleContent || articleExcerpt || articleTitle;
            const expandedContent = await expandArticleContent(articleTitle, brief);
            setArticleContent(expandedContent);
        } catch (error) {
            alert('حدث خطأ أثناء الاتصال بالذكاء الاصطناعي.');
        } finally {
            setIsExpanding(false);
        }
    };

    const handleImportFromUrl = async () => {
        if (!importUrl) return;

        setIsImporting(true);
        try {
            let titleGuess = "مقال جديد";
            try {
               const urlParts = importUrl.split('/');
               const lastPart = urlParts[urlParts.length - 1] || urlParts[urlParts.length - 2];
               if (lastPart) {
                   titleGuess = decodeURIComponent(lastPart).replace(/-/g, ' ');
               }
            } catch (e) {}

            const generatedContent = await expandArticleContent(titleGuess, `اكتب مقالاً كاملاً عن: ${titleGuess}`);

            setArticleTitle(titleGuess);
            setArticleContent(generatedContent);
            setArticleExcerpt(generatedContent.substring(0, 150).replace(/<[^>]*>?/gm, '') + '...'); 
            setArticleCategory('مقال مستورد');

            alert('تم استيراد (توليد) المقال بنجاح! يمكنك الآن تعديله.');
        } catch (error) {
            alert('فشل الاستيراد. تأكد من الرابط.');
        } finally {
            setIsImporting(false);
        }
    };

    const handleSubmitArticle = (e: React.FormEvent) => {
        e.preventDefault();

        let formattedContent = articleContent;
        if (!articleContent.includes('<p>') && !articleContent.includes('<h3>')) {
             formattedContent = articleContent.split('\n').filter(line => line.trim() !== '').map(line => `<p>${line}</p>`).join('');
        }

        if (editingArticleId) {
            const updatedArticles = articles.map(art => {
                if (art.id === editingArticleId) {
                    return {
                        ...art,
                        title: articleTitle,
                        category: articleCategory,
                        excerpt: articleExcerpt,
                        content: formattedContent,
                        image: articleImage || art.image, 
                    };
                }
                return art;
            });
            onUpdateArticles(updatedArticles);
            alert('تم تعديل المقال بنجاح!');
        } else {
            const slug = articleTitle.trim().toLowerCase().replace(/\s+/g, '-').replace(/[^\w\u0600-\u06FF-]/g, '');
            const newArticle: Article = {
                id: String(Date.now()),
                slug: slug,
                title: articleTitle,
                category: articleCategory,
                excerpt: articleExcerpt,
                content: formattedContent,
                image: articleImage || 'https://picsum.photos/seed/new_article/800/600',
                date: new Date().toLocaleDateString('ar-EG')
            };
            onUpdateArticles([newArticle, ...articles]);
            alert('تم نشر المقال بنجاح!');
        }

        resetArticleForm();
    };

    return (
        <div className="min-h-screen bg-gray-100 flex flex-col">
            <div className="bg-slate-900 text-white p-4 shadow-md flex justify-between items-center sticky top-0 z-50">
                <div className="flex items-center gap-3">
                    <LayoutDashboard className="text-gold-500" />
                    <div>
                        <h1 className="font-heading font-bold text-xl">لوحة التحكم</h1>
                        <div className="flex items-center gap-1 text-[10px]">
                            {isCloud ? (
                                <span className="text-green-400 flex items-center gap-1"><Cloud size={10} /> متصل بالسيرفر العالمي</span>
                            ) : (
                                <span className="text-orange-400 flex items-center gap-1"><CloudOff size={10} /> وضع محلي (تخزين مؤقت)</span>
                            )}
                        </div>
                    </div>
                </div>
                <button 
                    onClick={onLogout}
                    className="flex items-center gap-2 text-sm bg-slate-800 hover:bg-slate-700 px-4 py-2 rounded-lg transition-colors"
                >
                    <LogOut size={16} />
                    خروج
                </button>
            </div>

            <div className="container mx-auto p-4 md:p-6">
                <div className="flex gap-4 mb-8 bg-white p-2 rounded-xl shadow-sm max-w-6xl overflow-x-auto">
                    <button onClick={() => setActiveTab('testimonials')} className={`flex-1 py-3 px-4 rounded-lg font-bold flex items-center justify-center gap-2 transition-all min-w-[140px] ${activeTab === 'testimonials' ? 'bg-slate-900 text-white shadow' : 'text-gray-500 hover:bg-gray-50'}`}><Quote size={20} /> الآراء والصور</button>
                    <button onClick={() => setActiveTab('videos')} className={`flex-1 py-3 px-4 rounded-lg font-bold flex items-center justify-center gap-2 transition-all min-w-[140px] ${activeTab === 'videos' ? 'bg-red-600 text-white shadow' : 'text-gray-500 hover:bg-gray-50'}`}><VideoIcon size={20} /> الفيديوهات</button>
                    <button onClick={() => setActiveTab('about')} className={`flex-1 py-3 px-4 rounded-lg font-bold flex items-center justify-center gap-2 transition-all min-w-[140px] ${activeTab === 'about' ? 'bg-gold-500 text-white shadow' : 'text-gray-500 hover:bg-gray-50'}`}><UserCheck size={20} /> صور السيرة</button>
                    <button onClick={() => setActiveTab('gallery')} className={`flex-1 py-3 px-4 rounded-lg font-bold flex items-center justify-center gap-2 transition-all min-w-[140px] ${activeTab === 'gallery' ? 'bg-amber-600 text-white shadow' : 'text-gray-500 hover:bg-gray-50'}`}><Images size={20} /> المعرض</button>
                    <button onClick={() => setActiveTab('articles')} className={`flex-1 py-3 px-4 rounded-lg font-bold flex items-center justify-center gap-2 transition-all min-w-[140px] ${activeTab === 'articles' ? 'bg-purple-600 text-white shadow' : 'text-gray-500 hover:bg-gray-50'}`}><Newspaper size={20} /> المقالات</button>
                    <button onClick={() => setActiveTab('settings')} className={`flex-1 py-3 px-4 rounded-lg font-bold flex items-center justify-center gap-2 transition-all min-w-[140px] ${activeTab === 'settings' ? 'bg-blue-600 text-white shadow' : 'text-gray-500 hover:bg-gray-50'}`}><Settings size={20} /> إعدادات السيرفر</button>
                </div>

                {activeTab === 'settings' ? (
                    <div className="max-w-3xl mx-auto bg-white p-8 rounded-2xl shadow-lg animate-fade-in-up">
                        <div className="flex items-center gap-3 mb-6 border-b pb-4">
                            <div className="w-12 h-12 bg-blue-100 text-blue-600 rounded-full flex items-center justify-center"><Cloud size={24} /></div>
                            <div>
                                <h2 className="text-2xl font-bold text-slate-900">ربط السيرفر العالمي (Firebase)</h2>
                                <p className="text-gray-500 text-sm">اجعل موقعك دولياً واحفظ البيانات بشكل دائم</p>
                            </div>
                        </div>

                        {isCloud ? (
                            <div className="bg-green-50 border border-green-200 rounded-xl p-6 text-center">
                                <Cloud size={48} className="text-green-500 mx-auto mb-4" />
                                <h3 className="text-xl font-bold text-green-700 mb-2">الموقع متصل بالسيرفر بنجاح!</h3>
                                <p className="text-green-600 mb-6">يتم الآن حفظ جميع البيانات (الفيديوهات والصور) في قاعدة البيانات السحابية وتظهر لكل الزوار حول العالم.</p>
                                <button onClick={handleDisconnect} className="px-6 py-2 bg-red-100 text-red-600 rounded-lg hover:bg-red-200 font-bold transition-colors">قطع الاتصال</button>
                            </div>
                        ) : (
                            <div className="space-y-6">
                                <div className="bg-blue-50 p-4 rounded-lg text-sm text-blue-800 leading-relaxed">
                                    <strong>تعليمات الربط:</strong>
                                    <ol className="list-decimal list-inside mt-2 space-y-1">
                                        <li>اذهب إلى <a href="https://console.firebase.google.com/" target="_blank" className="underline font-bold">console.firebase.google.com</a> وأنشئ مشروعاً جديداً.</li>
                                        <li>اختر <strong>Firestore Database</strong> وأنشئ قاعدة بيانات.</li>
                                        <li>اذهب إلى <strong>Project Settings</strong> وانسخ كود SDK Config.</li>
                                    </ol>
                                </div>

                                <div>
                                    <label className="block font-bold text-gray-700 mb-2">لصق كود الإعدادات (JSON أو JS) هنا:</label>
