      6. قسم المقال إلى فقرتين أو ثلاث فقرات كحد أقصى.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
    });

    return response.text || "";
  } catch (error) {
    console.error("Article expansion failed:", error);
    throw error;
  }
};

